,39.4225192,-111.714358,NULL,NULL,NULL,'2024-11-09 00:00:00','2026-03-06 18:27:03'),('fffb1ba9-4abd-11f0-bbc5-06479488ad4b','Kevin Ratz','','',NULL,'','North Vernon','UT','',40.337368,-112.0114343,NULL,NULL,NULL,'2025-03-24 00:00:00','2026-03-06 18:30:51'),('fffbb6f7-4abd-11f0-bbc5-06479488ad4b','Kevin Tackett','kevint57@hotmail.com','',NULL,'','','UT','',39.4225192,-111.714358,NULL,NULL,NULL,'2025-06-16 14:27:15','2026-03-06 18:24:01'),('fffc7691-4abd-11f0-bbc5-06479488ad4b','James M Clark','JIM@KINETIKSCONSULTING.COM','(253) 332-2032',NULL,'','Phoenix','AZ','',33.4484367,-112.074141,'',NULL,NULL,'2025-06-16 14:27:15','2026-03-06 18:52:11'),('ffff3ac2-4abd-11f0-bbc5-06479488ad4b','Kris Lunt','','(801) 513-6600',NULL,'','West Jordan','UT','',40.6061337,-111.9395211,NULL,NULL,NULL,'2025-02-02 00:00:00','2026-03-06 18:30:53'),('ffff8a99-4abd-11f0-bbc5-06479488ad4b','Kurt Johnson','mrgoodwrench72@yahoo.com','2073999092',NULL,'','Madison','UT','',40.2412081,-111.6511972,NULL,NULL,NULL,'2025-06-16 14:27:15','2026-03-06 18:24:02');
