DROP TABLE IF EXISTS `content`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `content` (
  `id` varchar(36) NOT NULL DEFAULT uuid(),
  `title` varchar(255) NOT NULL,
  `slug` varchar(255) NOT NULL,
  `content` text DEFAULT NULL,
  `content_mode` enum('rich_text','blocks') DEFAULT 'rich_text',
  `image_url` varchar(500) DEFAULT NULL,
  `type_id` varchar(36) DEFAULT NULL,
  `published` tinyint(1) DEFAULT 0,
  `published_date` timestamp NULL DEFAULT NULL,
  `author_id` varchar(36) DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT current_timestamp(),
  `updated_at` timestamp NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  PRIMARY KEY (`id`),
  UNIQUE KEY `slug` (`slug`),
  KEY `idx_content_type` (`type_id`),
  KEY `idx_content_author` (`author_id`),
  KEY `idx_content_published` (`published`),
  CONSTRAINT `content_ibfk_1` FOREIGN KEY (`type_id`) REFERENCES `content_types` (`id`),
  CONSTRAINT `content_ibfk_2` FOREIGN KEY (`author_id`) REFERENCES `users` (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

