INSERT INTO `content` VALUES ('08adf52b-7785-11f0-8e76-0637a5b9918d','How To Make Decisions On Your Solar Project','how-to-make-decisions-on-your-solar-project','<p></p>','blocks',NULL,'1fcffdc6-4a02-11f0-bbc5-06479488ad4b',1,NULL,'ef51a3dc-4a38-11f0-bbc5-06479488ad4b','2025-08-12 14:02:50','2025-08-20 17:49:53'),('1672d4cf-7606-11f0-9a75-0637a5b9918d','Customer Projects','customer-projects',NULL,'blocks',NULL,'1fcffdc6-4a02-11f0-bbc5-06479488ad4b',1,'2025-08-10 00:00:00','ef51a3dc-4a38-11f0-bbc5-06479488ad4b','2025-08-10 16:21:36','2025-11-23 18:59:58'),('2490bbca-8126-11f0-8e5b-0637a5b9918d','Payoff Solar Summer Sale, Tax Credit, HB340, And Installation','payoff-solar-summer-sale-tax-credit-hb340-and-installation','<p>Hey there, it\'s Matt from Payoff Solar (<a target=\"_blank\" rel=\"noopener noreferrer nofollow\" class=\"text-blue-600 underline\" href=\"https://payoffsolar.com/\">https://payoffsolar.com/</a> - previously known as Utah Solar For All). We hope you have had a fun and sunny summer!</p><p></p><p><strong>Thank You</strong></p><p>Thank you all for making us successful! Since we started in October of last year, we have been able to help over 600 people get 5,000 solar panels! Thank you for helping us continue our quest to flood the earth with affordable solar!</p><p></p><p><strong>End Of Summer Sale and Current Inventory</strong></p><p>We are throwing an end-of-summer sale to blow out our current inventory! All of our products are listed on <a target=\"_blank\" rel=\"noopener noreferrer nofollow\" class=\"text-blue-600 underline\" href=\"https://payoffsolar.com/products\">https://payoffsolar.com/products</a>.</p><ul><li><p>New Black&nbsp;Alexus 405 Watt Solar Panels - these continue to be our bestseller, and we have about 600 left. We are clearing out these items for the end of summer to sell the remaining stock. They are on sale now for $99 each (they are $145 on SanTan Solar (<a target=\"_blank\" rel=\"noopener noreferrer nofollow\" class=\"text-blue-600 underline\" href=\"https://www.santansolar.com/product/alexus-solar-400w-mono-solar-panel/\">https://www.santansolar.com/product/alexus-solar-400w-mono-solar-panel/</a>), not including shipping). If you purchase 10-20, the price is $95 each, and for orders exceeding 20, the price is $90 each. See <a target=\"_blank\" rel=\"noopener noreferrer nofollow\" class=\"text-blue-600 underline\" href=\"https://payoffsolar.com/product/alexus-405-watt-black-solar-panel-alex-405-b54-s\">https://payoffsolar.com/product/alexus-405-watt-black-solar-panel-alex-405-b54-s</a></p></li><li><p>Used Silver SunPower 425 Watt Solar Panels - These are on sale now for $80 each. If you purchase 10-20, the price is $75 each, and for orders exceeding 20, the price is $70 each. These panels are the best bang for as low as $0.16/watt! See <a target=\"_blank\" rel=\"noopener noreferrer nofollow\" class=\"text-blue-600 underline\" href=\"https://payoffsolar.com/product/sunpower-435-watt-solar-panel-spr-435ne-wht-d\">https://payoffsolar.com/product/sunpower-435-watt-solar-panel-spr-435ne-wht-d</a></p></li><li><p>Inverters - we primarily have Growatt and EG4 string inverters, and&nbsp;APsystems microinverters - see <a target=\"_blank\" rel=\"noopener noreferrer nofollow\" class=\"text-blue-600 underline\" href=\"https://payoffsolar.com/products/category/inverters\">https://payoffsolar.com/products/category/inverters</a></p></li><li><p>Batteries - the&nbsp;EG4, Growatt, and LG batteries are the most popular that you can get from us - see <a target=\"_blank\" rel=\"noopener noreferrer nofollow\" class=\"text-blue-600 underline\" href=\"https://payoffsolar.com/products/category/batteries\">https://payoffsolar.com/products/category/batteries</a></p></li><li><p>Mounting Systems - we have always offered Unistrut and clamps (see <a target=\"_blank\" rel=\"noopener noreferrer nofollow\" class=\"text-blue-600 underline\" href=\"https://payoffsolar.com/products/category/mounting-systems\">https://payoffsolar.com/products/category/mounting-systems</a>), but we are starting to also offer affordable QuickBolt (<a target=\"_blank\" rel=\"noopener noreferrer nofollow\" class=\"text-blue-600 underline\" href=\"https://quickbolt.com/\">https://quickbolt.com/</a>) mounts and IronRidge (<a target=\"_blank\" rel=\"noopener noreferrer nofollow\" class=\"text-blue-600 underline\" href=\"https://www.ironridge.com/\">https://www.ironridge.com/</a>) rails - let me know if you are interested.</p></li></ul><p></p><p><strong>Signature Solar Reseller</strong></p><p>We have also become a reseller for Signature Solar (<a target=\"_blank\" rel=\"noopener noreferrer nofollow\" class=\"text-blue-600 underline\" href=\"https://signaturesolar.com/\">https://signaturesolar.com/</a>),&nbsp;so we get you great deals (15-20% off) on anything they sell, particularly on EG4 hybrid inverters, batteries, etc.. Let us know if you are interested in purchasing other equipment.</p><p></p><p><strong>Federal 30% Tax Credit Going Away</strong></p><p>You may have heard, but the Big Beautiful Bill was signed into law, which means that the 30% tax credit for installing solar is going away at the end of the year. Homeowners who have their solar systems installed by the end of 2025 can still claim the 30% credit, but those installing after this date will not be eligible. So, hurry and get your solar installed in the next 5 months!</p><p></p><p><strong>Utah House Bill 340</strong></p><p>If you live in Utah, you may have heard of House Bill 340 (<a target=\"_blank\" rel=\"noopener noreferrer nofollow\" class=\"text-blue-600 underline\" href=\"https://le.utah.gov/~2025/bills/static/HB0340.html\">https://le.utah.gov/~2025/bills/static/HB0340.html</a>), which now allows you to generate and backfeed&nbsp;1200 watts into your house without getting any approval, so instead of taking weeks/months to get&nbsp;your power company to approve a net metering setup, you can be up and running in less than an hour. Many of our customers are buying the EcoFlow Stream (<a target=\"_blank\" rel=\"noopener noreferrer nofollow\" class=\"text-blue-600 underline\" href=\"https://www.ecoflow.com/us/stream-microinverter\">https://www.ecoflow.com/us/stream-microinverter</a>) inverter for $300 and then 3-4 solar panels from us for $200-400,&nbsp;and then plugging it into one of their outlets, and they have a system that is saving them $15-20 per month on their energy bill. This will pay itself off within a couple of years and is a fun and inexpensive way to get started with solar. It is also great if you rent an apartment and can\'t do a full setup. We also have some kits using APsystems inverters for this too - see <a target=\"_blank\" rel=\"noopener noreferrer nofollow\" class=\"text-blue-600 underline\" href=\"https://payoffsolar.com/product/tricky-1600-watt-kit-w-monitoring-trick-bundle-1600-monitoring\">https://payoffsolar.com/product/tricky-1600-watt-kit-w-monitoring-trick-bundle-1600-monitoring</a></p><p></p><p><strong>Installation</strong></p><p>Let us know if you are interested in getting help with installing your system. We have partnered up with a reasonably priced installer (all in it is $1.50 per watt, which is half the price other installers charge), and you can just pay for what you need help with to lower your costs further. See our pricing packages at <a target=\"_blank\" rel=\"noopener noreferrer nofollow\" class=\"text-blue-600 underline\" href=\"https://payoffsolar.com/pricing\">https://payoffsolar.com/pricing</a>. You can also use our Solar Calculator on <a target=\"_blank\" rel=\"noopener noreferrer nofollow\" class=\"text-blue-600 underline\" href=\"https://payoffsolar.com/\">https://payoffsolar.com/</a> to get a feel for the prices on your project.</p><p></p><p><strong>Loyalty Program</strong></p><p>You get $5 off per panel if you do a repeat order because we love our loyal customers!</p><p></p><p><strong>Referral Program</strong></p><p>We will pay you $5 for each panel your referral purchases, so tell your family and friends! Be sure to have them mention that they were referred by you when they come to pick them up.</p><p></p><p><strong>Let Us Know</strong></p><p>You can text us at <a target=\"_blank\" rel=\"noopener noreferrer nofollow\" class=\"text-blue-600 underline\" href=\"tel:801-448-6396\">801-448-6396</a> if you have questions or if you want to get some solar panels or equipment.&nbsp; If you don\'t want to receive emails and/or texts like this from me, please text me or email me at <a target=\"_blank\" rel=\"noopener noreferrer nofollow\" class=\"text-blue-600 underline\" href=\"mailto:matt@payoffsolar.com\">matt@payoffsolar.com</a> and let me know if you want texts, emails, or neither.</p><p>Thanks, and have a great rest of your summer!</p><p>Matt Newman<br>11483 Wexford Way<br>South Jordan, UT 84009<br><a target=\"_blank\" rel=\"noopener noreferrer nofollow\" class=\"text-blue-600 underline\" href=\"tel:(801) 448-6396\">(801) 448-6396</a><br><a target=\"_blank\" rel=\"noopener noreferrer nofollow\" class=\"text-blue-600 underline\" href=\"mailto:matt@payoffsolar.com\">matt@payoffsolar.com</a></p><p>Kip Denning<br>11547 S Summer Stone Dr<br>South Jordan UT 84009<br><a target=\"_blank\" rel=\"noopener noreferrer nofollow\" class=\"text-blue-600 underline\" href=\"tel:(801) 556-8742\">(801) 556-8742</a></p><p>JD McBride<br>9102 N Government Creek Rd<br>Palmer, AK 99645<br><a target=\"_blank\" rel=\"noopener noreferrer nofollow\" class=\"text-blue-600 underline\" href=\"tel:(801) 686-1450\">(801) 686-1450</a></p>','rich_text','/uploads/products/1756066274889-tgpyh125q9.jpeg','1fcfff44-4a02-11f0-bbc5-06479488ad4b',1,'2025-08-24 00:00:00','ef51a3dc-4a38-11f0-bbc5-06479488ad4b','2025-08-24 20:08:47','2025-08-24 20:23:20'),('264f98a1-7186-11f0-9a85-0637a5b9918d','How To Build A Ground Mount Solar System','how-to-build-a-ground-mount-solar-system','<p>Jeff Rodgerson, one of our customers, built this amazing ground mount system using 12 Aptos 370 W solar panels, and EG4 6000XP hybrid inverter, and Vatrer lead acid batteries.&nbsp; These panels are bifacial so they also produce additional \"bifacial gain\" from the backside, in addition to the 370 W they generate from the front side.&nbsp;&nbsp;</p><p></p>','blocks','/uploads/products/1754348093615-l3v7clryigm.png','1fcffdc6-4a02-11f0-bbc5-06479488ad4b',1,'2025-08-04 22:55:43','ef51a3dc-4a38-11f0-bbc5-06479488ad4b','2025-08-04 22:55:43','2025-08-04 22:59:13'),('320279c6-7172-11f0-9a85-0637a5b9918d','Welcome To The New Website!','welcome-to-the-new-website','<p>Welcome to our new website and blog!&nbsp; We plan to keep you updated on the latest in solar and keep you informed.</p>','blocks','/uploads/products/1754341223595-io3ak7nukt.png','1fcfff44-4a02-11f0-bbc5-06479488ad4b',1,'2024-11-06 00:00:00','ef51a3dc-4a38-11f0-bbc5-06479488ad4b','2025-08-04 20:32:52','2025-08-12 13:33:26'),('43a6aae5-7065-11f0-9a55-0637a5b9918d','How-To Guides','how-to','This is how to do stuff','blocks',NULL,'1fcffdc6-4a02-11f0-bbc5-06479488ad4b',1,'2025-08-03 00:00:00','ef51a3dc-4a38-11f0-bbc5-06479488ad4b','2025-08-03 12:27:47','2025-08-12 14:07:17'),('61b24e06-7185-11f0-9a85-0637a5b9918d','Black Friday Sale','black-friday-sale','<p>Black Friday is upon us and we have some deals!</p><p><strong>New Panels</strong></p><p>I have&nbsp;some Aptos 370 W Bifacial Solar Panels that are on sale for $85 each, and $80 if you get 10 or more!&nbsp; This is $0.21 per watt, the lowest I have ever done.&nbsp; Check them out at&nbsp;<a target=\"_blank\" rel=\"noopener noreferrer nofollow\" class=\"text-blue-600 underline\" href=\"https://www.utahsolarforall.com/shop/aptos-370-watt-bifacial-mono-solar-panel-all-black-dna-120-bf26-370w-4\">https://www.utahsolarforall.com/shop/aptos-370-watt-bifacial-mono-solar-panel-all-black-dna-120-bf26-370w-4</a></p><p><strong>Used Panels</strong></p><p>I have some nice used Trina 250 W for $50 each, and $45 if you get 10 or more.&nbsp; Check them out at&nbsp;<a target=\"_blank\" rel=\"noopener noreferrer nofollow\" class=\"text-blue-600 underline\" href=\"https://www.utahsolarforall.com/shop/trina-solar-245-watt-solar-panel-tsm-245pa05-2\">https://www.utahsolarforall.com/shop/trina-solar-245-watt-solar-panel-tsm-245pa05-2</a></p>','rich_text','/uploads/products/1754347796403-l9wehtppbqm.png','1fcfff44-4a02-11f0-bbc5-06479488ad4b',1,'2024-11-20 00:00:00','ef51a3dc-4a38-11f0-bbc5-06479488ad4b','2025-08-04 22:50:13','2025-08-12 13:33:11'),('912a336c-7185-11f0-9a85-0637a5b9918d','Referral Program','referral-program','<p>Get paid to refer your friends!</p><p>I will pay you $5 for each panel your referral purchases, so tell your family and friends!</p><p>Be sure to have them mention that they were referred by you when they come to pick them up.</p>','rich_text','/uploads/products/1754347886358-g8xjnr9k3r.png','1fcfff44-4a02-11f0-bbc5-06479488ad4b',1,'2025-01-04 00:00:00','ef51a3dc-4a38-11f0-bbc5-06479488ad4b','2025-08-04 22:51:32','2025-08-12 13:33:38'),('ba86fd21-7185-11f0-9a85-0637a5b9918d','Loyalty Program','loyalty-program','<p>Our loyal customers can get deals</p><p>We want to treat our loyal customers right, so you get $5 off per panel if you do a repeat order.&nbsp; Please let me know when you order so I can be sure to give you your discount.</p>','rich_text','/uploads/products/1754347960988-dcixxzpa1uv.png','1fcfff44-4a02-11f0-bbc5-06479488ad4b',1,'2025-02-17 00:00:00','ef51a3dc-4a38-11f0-bbc5-06479488ad4b','2025-08-04 22:52:42','2025-08-12 13:33:56'),('c05bd47f-7152-11f0-9a85-0637a5b9918d','How To Install Unistrut Racking System Yourself','how-to-install-unistrut-racking-system-yourself',NULL,'blocks','/uploads/products/1754594251805-v8b69p09ca.png','1fcffdc6-4a02-11f0-bbc5-06479488ad4b',1,'2025-08-04 00:00:00','ef51a3dc-4a38-11f0-bbc5-06479488ad4b','2025-08-04 16:47:47','2025-08-07 19:23:32'),('edeb9527-7185-11f0-9a85-0637a5b9918d','How To Get Help On Your Solar Project','how-to-get-help-on-your-solar-project','<h2><strong>Overview</strong></h2><hr><p>If you need help on your solar project (including project plans, permitting, installation labor, tax credit, financing, warranty, etc), you can use some of our partners here.&nbsp; Let them know we sent you, and we can make sure to get you the equipment you need with their help.&nbsp;</p><h2><strong>Partners</strong></h2><hr><p>These folks can&nbsp;help you design a new system, or add to an existing system, whether it is rooftop solar, ground-mounted, or on a vehicle (e.g., RV, van, etc.).&nbsp; They can help with your solar panels, inverters, charge controllers, and batteries.</p><h4><strong>Rooftop Solar</strong></h4><ul><li><p>New And Existing Systems</p><ul><li><p>Richard <a target=\"_blank\" rel=\"noopener noreferrer nofollow\" class=\"text-blue-600 underline\" href=\"tel:(801) 941-7541\">(801) 941-7541</a> - low-cost provider - $1.80/Watt</p></li><li><p>Israel/Bat - (435) 513-4853 - low-cost provider - $1.80/Watt</p></li><li><p><a target=\"_blank\" rel=\"noopener noreferrer nofollow\" class=\"text-blue-600 underline\" href=\"https://www.linkedin.com/in/jonas-christensen-35b59123b/\">Jonas Christensen</a>, Service&nbsp;Connect, <a target=\"_blank\" rel=\"noopener noreferrer nofollow\" class=\"text-blue-600 underline\" href=\"tel:(435) 668-9271\">(435) 668-9271</a> - get help with installation and roofing</p></li><li><p>Tony Paskins, DIY Sun Energy, <a target=\"_blank\" rel=\"noopener noreferrer nofollow\" class=\"text-blue-600 underline\" href=\"tel:(801) 388-0180\">(801) 388-0180</a></p></li><li><p>Ivan Cabrera, Solar Maintenace LLC (801) 917-7429</p></li></ul></li><li><p>New Installation Only</p><ul><li><p><a target=\"_blank\" rel=\"noopener noreferrer nofollow\" class=\"text-blue-600 underline\" href=\"https://solarwholesale.com/\">Solar Wholesale</a>&nbsp;- get help with permitting, installation, and DIY solar kits</p></li><li><p>Gerald Johnson,&nbsp;Deseret Renewable Energy, <a target=\"_blank\" rel=\"noopener noreferrer nofollow\" class=\"text-blue-600 underline\" href=\"tel:(801) 336-7469\">(801) 336-7469</a>, <a target=\"_blank\" rel=\"noopener noreferrer nofollow\" class=\"text-blue-600 underline\" href=\"mailto:gerald.consulting.services@gmail.com\">gerald.consulting.services@gmail.com</a> - $3/Watt</p></li><li><p><a target=\"_blank\" rel=\"noopener noreferrer nofollow\" class=\"text-blue-600 underline\" href=\"https://projectsolar.com/\">Project Solar</a></p></li><li><p><a target=\"_blank\" rel=\"noopener noreferrer nofollow\" class=\"text-blue-600 underline\" href=\"https://gospringsolarnow.com/\">Spring Solar</a></p></li></ul></li></ul><h4><strong>RV/Van Solar</strong></h4><ul><li><p>James Massinelli,&nbsp;<a target=\"_blank\" rel=\"noopener noreferrer nofollow\" class=\"text-blue-600 underline\" href=\"tel:(239) 248-7967\">(239) 248-7967</a>, <a target=\"_blank\" rel=\"noopener noreferrer nofollow\" class=\"text-blue-600 underline\" href=\"https://www.instagram.com/jims_vans/\">Instagram</a></p></li><li><p>Jon Shumway, Off-Grid Solar, <a target=\"_blank\" rel=\"noopener noreferrer nofollow\" class=\"text-blue-600 underline\" href=\"tel:(801) 675-8518\">(801) 675-8518</a>, <a target=\"_blank\" rel=\"noopener noreferrer nofollow\" class=\"text-blue-600 underline\" href=\"mailto:offgridsolar.jon@gmail.com\">offgridsolar.jon@gmail.com</a></p></li><li><p>Ready RV Services, <a target=\"_blank\" rel=\"noopener noreferrer nofollow\" class=\"text-blue-600 underline\" href=\"tel:(385) 254-1177\">(385) 254-1177</a></p></li><li><p>Todd Anderson, <a target=\"_blank\" rel=\"noopener noreferrer nofollow\" class=\"text-blue-600 underline\" href=\"tel:(801) 915-5443\">(801) 915-5443</a></p></li><li><p>Mike Brown, Camper World, (801) 390-7700</p></li></ul><h2><strong>Resources</strong></h2><hr><p>These are some resources that can help you with your solar project.</p><h4><strong>Online Forums</strong></h4><ul><li><p><a target=\"_blank\" rel=\"noopener noreferrer nofollow\" class=\"text-blue-600 underline\" href=\"https://diysolarforum.com/\">DIY Solar Forum</a></p></li></ul><h4><strong>Online Video Channels</strong></h4><ul><li><p><a target=\"_blank\" rel=\"noopener noreferrer nofollow\" class=\"text-blue-600 underline\" href=\"https://www.youtube.com/@WillProwse\">DIY Solar Power with Will Prowse</a></p></li><li><p><a target=\"_blank\" rel=\"noopener noreferrer nofollow\" class=\"text-blue-600 underline\" href=\"https://www.youtube.com/@theresatrickforthat\">There\'s A Trick For That YouTube Channel</a>&nbsp;(solar projects you can do around your house)</p></li></ul><p></p>','rich_text','/uploads/products/1754348031131-vmx0qxsndz.png','1fcffdc6-4a02-11f0-bbc5-06479488ad4b',1,'2025-08-04 00:00:00','ef51a3dc-4a38-11f0-bbc5-06479488ad4b','2025-08-04 22:54:08','2025-11-22 17:34:12');
