CREATE TABLE `content_blocks` (
  `id` varchar(36) NOT NULL DEFAULT uuid(),
  `content_id` varchar(36) NOT NULL,
  `block_type_id` varchar(36) NOT NULL,
  `block_order` int(11) NOT NULL DEFAULT 0,
  `configuration` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL CHECK (json_valid(`configuration`)),
  `created_at` timestamp NULL DEFAULT current_timestamp(),
  `updated_at` timestamp NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  PRIMARY KEY (`id`),
  KEY `block_type_id` (`block_type_id`),
  KEY `idx_content_blocks_content_order` (`content_id`,`block_order`),
  CONSTRAINT `content_blocks_ibfk_1` FOREIGN KEY (`content_id`) REFERENCES `content` (`id`) ON DELETE CASCADE,
  CONSTRAINT `content_blocks_ibfk_2` FOREIGN KEY (`block_type_id`) REFERENCES `block_types` (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;
