INSERT INTO `content_blocks` VALUES ('0187b8b4-73c4-11f0-9985-0637a5b9918d','c05bd47f-7152-11f0-9a85-0637a5b9918d','5b734f7e-70ca-11f0-9a55-0637a5b9918d',0,'{\"title\":\"\",\"subtitle\":\"\",\"textAlign\":\"center\",\"backgroundImage\":\"/uploads/products/1754326054364-ivlcjps206d.png\"}','2025-08-07 19:23:32','2025-08-07 19:23:32'),('018f571b-73c4-11f0-9985-0637a5b9918d','c05bd47f-7152-11f0-9a85-0637a5b9918d','5b738254-70ca-11f0-9a55-0637a5b9918d',1,'{\"content\":\"<p><em>Matt describes how he replaced his original treated lumber racking system with a Unistrut one, which are both much less expensive alternatives to a pre-built system.</em></p>\",\"textAlign\":\"left\"}','2025-08-07 19:23:32','2025-08-07 19:23:32'),('0197a829-73c4-11f0-9985-0637a5b9918d','c05bd47f-7152-11f0-9a85-0637a5b9918d','5b738254-70ca-11f0-9a55-0637a5b9918d',2,'{\"content\":\"<h3>Install</h3><p>This video shows you how I replaced my rooftop solar racking system that I installed in 2017 that was made with treated lumber.&nbsp;</p><h3>Replacement Of Original System</h3><p>It originally cost only $350 (for a 7kW system), but after 7 years, it was falling apart and the panels were sliding down. So I replaced it with a still inexpensive racking system using Unistrut (and common hardware from Home Depot or Lowes) that cost a total of $700, much better than the $2,000-$3,000 pre-built systems (e.g., Unirac, IronRidge, SnapNRack, etc.) you can purchase.</p>\",\"textAlign\":\"left\"}','2025-08-07 19:23:32','2025-08-07 19:23:32'),('019f598c-73c4-11f0-9985-0637a5b9918d','c05bd47f-7152-11f0-9a85-0637a5b9918d','5b738538-70ca-11f0-9a55-0637a5b9918d',3,'{\"url\":\"https://www.youtube.com/watch?v=OCWGJzXDud0\",\"title\":\"\",\"description\":\"\",\"autoplay\":false}','2025-08-07 19:23:32','2025-08-07 19:23:32'),('13fc8099-7dee-11f0-8e5b-0637a5b9918d','08adf52b-7785-11f0-8e76-0637a5b9918d','5b738254-70ca-11f0-9a55-0637a5b9918d',0,'{\"content\":\"<p>This is information about some decisions you will need to make for your solar project.&nbsp; Use this tool to generate a task list, equipment list, and decision flow documents.</p>\",\"textAlign\":\"left\"}','2025-08-20 17:49:53','2025-08-20 17:49:53'),('14041f02-7dee-11f0-8e5b-0637a5b9918d','08adf52b-7785-11f0-8e76-0637a5b9918d','5b738254-70ca-11f0-9a55-0637a5b9918d',1,'{\"content\":\"<h3><strong>Where You Will Put It?</strong></h3><p>You need to decide where you will put your solar equipment.</p><ul><li><p>Stationary</p><ul><li><p>Rooftop</p><ul><li><p>Angled&nbsp;(e.g., house, shed, cabin, barn, pavilion, cabana, gazebo, etc.)</p></li><li><p>Flat&nbsp;(e.g., building, carport, arbor, pergola, tiny home, shipping container, etc.)</p></li></ul></li><li><p>Ground Mount</p></li></ul></li><li><p>Mobile</p><ul><li><p>Powered (e.g., RV, motor home, camper, van, bus, moving truck, truck camper, etc.)</p></li><li><p>Non-powered</p><ul><li><p>Roofed (e.g., travel trailer, toy/car hauler, pop-up trailer, fifth wheel trailer, semi trailer, etc.)</p></li><li><p>Non-roofed (e.g., flatbed trailer, gooseneck trailer, solar trailer, etc.)</p></li></ul></li></ul></li></ul>\",\"textAlign\":\"left\"}','2025-08-20 17:49:53','2025-08-20 17:49:53'),('140bfefc-7dee-11f0-8e5b-0637a5b9918d','08adf52b-7785-11f0-8e76-0637a5b9918d','5b738254-70ca-11f0-9a55-0637a5b9918d',2,'{\"content\":\"<h3><strong>Who Will Do The Work?</strong></h3><p>You need to decide on how much you want to do yourself and how much you want to hire someone else (usually a solar installation company) to do.&nbsp; If you chose a stationary option previously, you have many more options for getting help.</p><p></p><p>Services typically include:</p><ul><li><p>Equipment Purchase</p></li><li><p>Equipment Delivery&nbsp;</p></li><li><p>Permitting</p><ul><li><p>City Permit</p></li><li><p>Power Company Grid-Tie Approval</p></li><li><p>HOA Approval</p></li></ul></li></ul><ul><li><p>Installation</p><ul><li><p>Racking/Mounting Hardware Installation</p></li><li><p>Solar Panel Mounting</p></li><li><p>Wiring</p></li></ul></li></ul><ul><li><p>Financing</p></li><li><p>Warranty</p></li><li><p>Tax Credit</p></li></ul><p>These service models are&nbsp;referred to as&nbsp;Full-Service,&nbsp;Hybrid (A La Carte), and DIY.</p><table class=\\\"table-auto border-collapse border border-gray-300\\\" style=\\\"min-width: 100px\\\"><colgroup><col style=\\\"min-width: 25px\\\"><col style=\\\"min-width: 25px\\\"><col style=\\\"min-width: 25px\\\"><col style=\\\"min-width: 25px\\\"></colgroup><tbody><tr class=\\\"\\\"><td class=\\\"border border-gray-300 p-2\\\" colspan=\\\"1\\\" rowspan=\\\"1\\\"><p><strong>Comparison Dimension</strong></p></td><td class=\\\"border border-gray-300 p-2\\\" colspan=\\\"1\\\" rowspan=\\\"1\\\"><p><strong>Full Service Model</strong></p></td><td class=\\\"border border-gray-300 p-2\\\" colspan=\\\"1\\\" rowspan=\\\"1\\\"><p><strong>Hybrid (A La Carte) Model</strong></p></td><td class=\\\"border border-gray-300 p-2\\\" colspan=\\\"1\\\" rowspan=\\\"1\\\"><p><strong>DIY Model</strong></p></td></tr><tr class=\\\"\\\"><td class=\\\"border border-gray-300 p-2\\\" colspan=\\\"1\\\" rowspan=\\\"1\\\"><p>Description</p></td><td class=\\\"border border-gray-300 p-2\\\" colspan=\\\"1\\\" rowspan=\\\"1\\\"><p>You hire a solar company&nbsp;to do everything</p></td><td class=\\\"border border-gray-300 p-2\\\" colspan=\\\"1\\\" rowspan=\\\"1\\\"><p>You do some&nbsp;</p></td><td class=\\\"border border-gray-300 p-2\\\" colspan=\\\"1\\\" rowspan=\\\"1\\\"><p>You&nbsp;do everything yourself</p></td></tr><tr class=\\\"\\\"><td class=\\\"border border-gray-300 p-2\\\" colspan=\\\"1\\\" rowspan=\\\"1\\\"><p>​Ease/Convenience</p></td><td class=\\\"border border-gray-300 p-2\\\" colspan=\\\"1\\\" rowspan=\\\"1\\\"><p>Easy​</p></td><td class=\\\"border border-gray-300 p-2\\\" colspan=\\\"1\\\" rowspan=\\\"1\\\"><p>Moderate</p></td><td class=\\\"border border-gray-300 p-2\\\" colspan=\\\"1\\\" rowspan=\\\"1\\\"><p>Hard</p></td></tr><tr class=\\\"\\\"><td class=\\\"border border-gray-300 p-2\\\" colspan=\\\"1\\\" rowspan=\\\"1\\\"><p>Cost</p></td><td class=\\\"border border-gray-300 p-2\\\" colspan=\\\"1\\\" rowspan=\\\"1\\\"><p>High</p></td><td class=\\\"border border-gray-300 p-2\\\" colspan=\\\"1\\\" rowspan=\\\"1\\\"><p>Medium</p></td><td class=\\\"border border-gray-300 p-2\\\" colspan=\\\"1\\\" rowspan=\\\"1\\\"><p>Low</p></td></tr><tr class=\\\"\\\"><td class=\\\"border border-gray-300 p-2\\\" colspan=\\\"1\\\" rowspan=\\\"1\\\"><p>Ability To Maintain/Fix</p></td><td class=\\\"border border-gray-300 p-2\\\" colspan=\\\"1\\\" rowspan=\\\"1\\\"><p>Low</p></td><td class=\\\"border border-gray-300 p-2\\\" colspan=\\\"1\\\" rowspan=\\\"1\\\"><p>Moderate</p></td><td class=\\\"border border-gray-300 p-2\\\" colspan=\\\"1\\\" rowspan=\\\"1\\\"><p>High</p></td></tr><tr class=\\\"\\\"><td class=\\\"border border-gray-300 p-2\\\" colspan=\\\"1\\\" rowspan=\\\"1\\\"><p>Flexibility</p></td><td class=\\\"border border-gray-300 p-2\\\" colspan=\\\"1\\\" rowspan=\\\"1\\\"><p>Low</p></td><td class=\\\"border border-gray-300 p-2\\\" colspan=\\\"1\\\" rowspan=\\\"1\\\"><p>Moderate</p></td><td class=\\\"border border-gray-300 p-2\\\" colspan=\\\"1\\\" rowspan=\\\"1\\\"><p>High</p></td></tr><tr class=\\\"\\\"><td class=\\\"border border-gray-300 p-2\\\" colspan=\\\"1\\\" rowspan=\\\"1\\\"><p>Pizza Analog</p></td><td class=\\\"border border-gray-300 p-2\\\" colspan=\\\"1\\\" rowspan=\\\"1\\\"><p>Domino\'s, Pizza Hut,&nbsp;Little Caesars (ready-made pizza - you just get to enjoy)</p></td><td class=\\\"border border-gray-300 p-2\\\" colspan=\\\"1\\\" rowspan=\\\"1\\\"><p>Papa Murphy\'s (they make it, you cook it)</p></td><td class=\\\"border border-gray-300 p-2\\\" colspan=\\\"1\\\" rowspan=\\\"1\\\"><p>Pizza From Scratch (you buy pizza components at grocery store and make your own pizza)</p></td></tr><tr class=\\\"\\\"><td class=\\\"border border-gray-300 p-2\\\" colspan=\\\"1\\\" rowspan=\\\"1\\\"><p>Gas Analog</p></td><td class=\\\"border border-gray-300 p-2\\\" colspan=\\\"1\\\" rowspan=\\\"1\\\"><p>Full Service Gas Station (they pump it for you)</p></td><td class=\\\"border border-gray-300 p-2\\\" colspan=\\\"1\\\" rowspan=\\\"1\\\"><p>Self Service Gas Station (they provide the gas, you pump it)</p></td><td class=\\\"border border-gray-300 p-2\\\" colspan=\\\"1\\\" rowspan=\\\"1\\\"><p>DIY Gas (you get it out of the ground, refine it, and pump it into your car)</p></td></tr><tr class=\\\"\\\"><td class=\\\"border border-gray-300 p-2\\\" colspan=\\\"1\\\" rowspan=\\\"1\\\"><p>Car&nbsp;Analog</p></td><td class=\\\"border border-gray-300 p-2\\\" colspan=\\\"1\\\" rowspan=\\\"1\\\"><p>Dealership&nbsp;(they warranty it, provide the shop and tools, they maintain and fix it)</p></td><td class=\\\"border border-gray-300 p-2\\\" colspan=\\\"1\\\" rowspan=\\\"1\\\"><p>Mechanic (they provide the shop and tools, they fix it and warranty only the repair they did)</p><p>Self-Service Mechanic (they provide shop, you fix it yourself)</p></td><td class=\\\"border border-gray-300 p-2\\\" colspan=\\\"1\\\" rowspan=\\\"1\\\"><p>DIY Car Repair (you provide shop and tools, you fix it)</p></td></tr><tr class=\\\"\\\"><td class=\\\"border border-gray-300 p-2\\\" colspan=\\\"1\\\" rowspan=\\\"1\\\"><p>Airfare Analog</p></td><td class=\\\"border border-gray-300 p-2\\\" colspan=\\\"1\\\" rowspan=\\\"1\\\"><p>Travel Agent (they buy tickets and plan your trip)</p></td><td class=\\\"border border-gray-300 p-2\\\" colspan=\\\"1\\\" rowspan=\\\"1\\\"><p>Travel Assistant (they buy your tickets, you plan the trip)</p></td><td class=\\\"border border-gray-300 p-2\\\" colspan=\\\"1\\\" rowspan=\\\"1\\\"><p>DIY Travel (you buy tickets and plan the entire trip)</p></td></tr><tr class=\\\"\\\"><td class=\\\"border border-gray-300 p-2\\\" colspan=\\\"1\\\" rowspan=\\\"1\\\"><p>Phone&nbsp;Analog</p></td><td class=\\\"border border-gray-300 p-2\\\" colspan=\\\"1\\\" rowspan=\\\"1\\\"><p>Apple Care (you get phone from Apple, they fix it)</p></td><td class=\\\"border border-gray-300 p-2\\\" colspan=\\\"1\\\" rowspan=\\\"1\\\"><p>Phone Repair Shop (you have to find and they fix it)</p></td><td class=\\\"border border-gray-300 p-2\\\" colspan=\\\"1\\\" rowspan=\\\"1\\\"><p>DIY Phone (you fix it if it breaks)</p></td></tr></tbody></table>\",\"textAlign\":\"left\"}','2025-08-20 17:49:54','2025-08-20 17:49:54'),('1414d405-7dee-11f0-8e5b-0637a5b9918d','08adf52b-7785-11f0-8e76-0637a5b9918d','5b738254-70ca-11f0-9a55-0637a5b9918d',3,'{\"content\":\"<h3><strong>What Equipment Will You Need?</strong></h3><p>You will need to decide on what equipment you want and how big of a system you need.&nbsp; You can use the equipment checklist.</p><p>Based on the type of system you want:</p><ul><li><p>Generation</p><ul><li><p>Solar Panels</p><ul><li><p>Price (e.g., $0.20/W, $0.45/W, etc.)</p></li><li><p>Brand/Warranty (Trina, Canadian Solar, JA Solar, Jinko, Yingli, Qcells, REC, Longi, Aptos, etc.)</p></li><li><p>Wattage (e.g., 250W, 300W, 370W, 400W, etc.)</p></li><li><p>Performance/Efficiency (e.g., 16%, 20%, 22%)</p></li><li><p>Durability (e.g., flexible, tempered glass, etc.)</p></li><li><p>Dimensions (e.g.,&nbsp;67.80 × 44.65 × 1.18 in)</p></li><li><p>Connector (e.g., MC4)</p></li><li><p>Module Color (e.g., Black,&nbsp;Blue)</p></li><li><p>Back Color (e.g., Black,&nbsp;White)</p></li><li><p>Frame Color (e.g., Silver, Black)</p></li><li><p>Faciality (e.g., Monofacial, Bifacial)</p></li><li><p>Cell Type (e.g., Mono, Poly)</p></li><li><p>Type (e.g.,&nbsp;Residential, Commercial)</p></li><li><p>Cable Length (e.g.,&nbsp;1200 MM)</p></li><li><p>Quantity (e.g., 1, 5, 10, 20, 30, etc.)</p></li></ul></li><li><p>Storage/Inversion</p><ul><li><p>Grid-Tie</p><ul><li><p>​Grid-Tie Inverter</p><ul><li><p>Micro Inverters</p></li><li><p>String Inverter (e.g., SunnyBoy/SMA, Tesla, etc.)</p></li></ul></li><li><p>Mounting Hardware</p></li><li><p>Wires</p></li><li><p>Combiner Box</p></li></ul></li><li><p>Off-Grid</p><ul><li><p>All-In-One Device</p><ul><li><p>Portable Power Station And Power Kits (e.g., EcoFlow, Bluetti, Jackery, etc.)</p></li></ul></li><li><p>Multiple Devices</p><ul><li><p>Off-Grid Inverter</p></li><li><p>Charge Controller</p></li><li><p>Batteries</p></li></ul></li></ul></li><li><p>Hybrid</p><ul><li><p>Hybrid Inverter (e.g., EG4, Sol-Ark,&nbsp;Growatt,&nbsp;Sungold Power, etc.)</p></li><li><p>Charge Controller</p></li><li><p>Batteries</p></li></ul></li></ul></li><li><p>Mounting Hardware</p><ul><li><p>Racking Hardware</p><ul><li><p>Lumber - $20/panel</p></li><li><p>Strut Channel (e.g., Unistrut, Superstrut, etc.) - $30/panel</p></li><li><p>Solar-Built Aluminum (<a target=\\\"_blank\\\" rel=\\\"noopener noreferrer nofollow\\\" class=\\\"text-blue-600 underline\\\" href=\\\"https://snapnrack.com/\\\">https://snapnrack.com/</a>,&nbsp;<a target=\\\"_blank\\\" rel=\\\"noopener noreferrer nofollow\\\" class=\\\"text-blue-600 underline\\\" href=\\\"https://unirac.com/\\\">https://unirac.com/</a>,&nbsp;<a target=\\\"_blank\\\" rel=\\\"noopener noreferrer nofollow\\\" class=\\\"text-blue-600 underline\\\" href=\\\"https://www.ironridge.com/\\\">https://www.ironridge.com/</a>, etc.) - $50/panel</p></li></ul></li><li><p>Clamps (e.g., mid-clamps, end-clamps, etc.)</p></li><li><p>Mounting</p><ul><li><p>QuickBolt (<a target=\\\"_blank\\\" rel=\\\"noopener noreferrer nofollow\\\" class=\\\"text-blue-600 underline\\\" href=\\\"https://quickbolt.com/\\\">https://quickbolt.com/</a><a target=\\\"_blank\\\" rel=\\\"noopener noreferrer nofollow\\\" class=\\\"text-blue-600 underline\\\" href=\\\"https://unirac.com/\\\">)</a></p></li></ul></li></ul></li></ul></li></ul>\",\"textAlign\":\"left\"}','2025-08-20 17:49:54','2025-08-20 17:49:54'),('141d2580-7dee-11f0-8e5b-0637a5b9918d','08adf52b-7785-11f0-8e76-0637a5b9918d','5b738254-70ca-11f0-9a55-0637a5b9918d',4,'{\"content\":\"<h3><strong>How Large Of A System Do I Need?</strong></h3><p>Some questions to consider when sizing your system are below.</p><ul><li><p>What will fit in the space you have?</p></li><li><p>How many kW do you need?</p></li><li><p>How much is your electric bill each month?</p></li><li><p>How many square feet is the home or vehicle?</p></li><li><p>Keep it simple - small, medium, large - don\'t overthink it</p></li><li><p>A good rule of thumb is 120% if you are doing grid-tie</p></li><li><p>Even if you can\'t get a system that covers all your power needs, it will save money and keep you out of the expensive tiers, so just do what you can afford</p></li></ul>\",\"textAlign\":\"left\"}','2025-08-20 17:49:54','2025-08-20 17:49:54'),('1424dc22-7dee-11f0-8e5b-0637a5b9918d','08adf52b-7785-11f0-8e76-0637a5b9918d','5b738254-70ca-11f0-9a55-0637a5b9918d',5,'{\"content\":\"<h3><strong>How Will You Pay For It?</strong></h3><p>You will need to decide on what ownership model you want and how to pay for it.</p><ul><li><p>Own It</p></li><li><p>Pay cash</p></li><li><p>Get a loan - Home Equity Line Of Credit (HELOC), personal bank loan, credit card, etc.</p></li></ul><ul><li><p>Lease It - lease it from the solar company</p></li><li><p>Do a Power Purchasing Agreement (PPA) - instead of paying a power bill, you pay the solar company each month</p></li></ul>\",\"textAlign\":\"left\"}','2025-08-20 17:49:54','2025-08-20 17:49:54'),('142d054d-7dee-11f0-8e5b-0637a5b9918d','08adf52b-7785-11f0-8e76-0637a5b9918d','5b7382fa-70ca-11f0-9a55-0637a5b9918d',6,'{\"image\":\"/uploads/products/1755712137130-124nj0nirhef.png\",\"caption\":\"\",\"alt\":\"\",\"size\":\"medium\"}','2025-08-20 17:49:54','2025-08-20 17:49:54'),('14361cdc-7dee-11f0-8e5b-0637a5b9918d','08adf52b-7785-11f0-8e76-0637a5b9918d','5b738254-70ca-11f0-9a55-0637a5b9918d',7,'{\"content\":\"<p>Enter your text here...</p>\",\"textAlign\":\"left\"}','2025-08-20 17:49:54','2025-08-20 17:49:54'),('143eb904-7dee-11f0-8e5b-0637a5b9918d','08adf52b-7785-11f0-8e76-0637a5b9918d','5b7382fa-70ca-11f0-9a55-0637a5b9918d',8,'{\"image\":\"/uploads/products/1755712151018-lx4y982yad9.png\",\"caption\":\"\",\"alt\":\"\",\"size\":\"medium\"}','2025-08-20 17:49:54','2025-08-20 17:49:54'),('1446d649-7dee-11f0-8e5b-0637a5b9918d','08adf52b-7785-11f0-8e76-0637a5b9918d','5b7382fa-70ca-11f0-9a55-0637a5b9918d',9,'{\"image\":\"/uploads/products/1755712158633-yzq723ovtob.png\",\"caption\":\"\",\"alt\":\"\",\"size\":\"medium\"}','2025-08-20 17:49:54','2025-08-20 17:49:54'),('144eb948-7dee-11f0-8e5b-0637a5b9918d','08adf52b-7785-11f0-8e76-0637a5b9918d','5b7382fa-70ca-11f0-9a55-0637a5b9918d',10,'{\"image\":\"/uploads/products/1755712166593-nxoypvlusx.png\",\"caption\":\"\",\"alt\":\"\",\"size\":\"medium\"}','2025-08-20 17:49:54','2025-08-20 17:49:54'),('1456bb63-7dee-11f0-8e5b-0637a5b9918d','08adf52b-7785-11f0-8e76-0637a5b9918d','5b7382fa-70ca-11f0-9a55-0637a5b9918d',11,'{\"image\":\"/uploads/products/1755712174586-t0o4599xonn.png\",\"caption\":\"\",\"alt\":\"\",\"size\":\"medium\"}','2025-08-20 17:49:54','2025-08-20 17:49:54'),('6815c679-7186-11f0-9a85-0637a5b9918d','264f98a1-7186-11f0-9a85-0637a5b9918d','5b734f7e-70ca-11f0-9a55-0637a5b9918d',0,'{\"title\":\"From Our Customers\",\"subtitle\":\"Jeff Rodgerson, one of our customers, built this amazing ground mount system using 12 Aptos 370 W solar panels, and EG4 6000XP hybrid inverter, and Vatrer lead acid batteries.  These panels are bifacial so they also produce additional \\\"bifacial gain\\\" from the backside, in addition to the 370 W they generate from the front side.  \",\"textAlign\":\"center\",\"backgroundImage\":\"/uploads/products/1754348132058-th5fufup18l.png\"}','2025-08-04 22:57:33','2025-08-04 22:57:33'),('681dea5e-7186-11f0-9a85-0637a5b9918d','264f98a1-7186-11f0-9a85-0637a5b9918d','5b738021-70ca-11f0-9a55-0637a5b9918d',1,'{\"title\":\"\",\"subtitle\":\"\",\"columns\":3,\"cards\":[{\"title\":\"Solar Panels\",\"description\":\"Get some panels that are good quality and low cost.  A good price is $0.20-$0.25 per watt and possible (half what the cost was five years ago).  If possible, get solar panels that are bifacial so you maximize generation, and try to put them on a white surface 3-4 feet high to maximize bifacial gain from the back side.  Also, you will likely want black ones that look nice and are less reflective. \",\"image\":\"/uploads/products/1754348176569-yd5rbysy11b.png\",\"link\":\"\",\"linkText\":\"\"},{\"title\":\"Racking\",\"description\":\"You can get aluminum specialty hardware that is usually $3-4 per foot.  We recommend unistrut, which is typically $2 per foot ($20 for a 10 foot stick) at a local electric supply store.  You will also need some mid and end clamps to clamp the panels down to the racking.\",\"image\":\"/uploads/products/1754348227961-efd4804g104.png\",\"link\":\"\",\"linkText\":\"\"},{\"title\":\"Inverter/Charge Controller/Batteries\",\"description\":\"You will want to get an inverter to convert the DC electricity coming from the panels to AC electricity that your home appliances can use.  There are also hybrid inverters like the EG4 6000XP that also allow you to have batteries along with your inverter.  It manages the power going to your house, and what is saved to the batteries. \",\"image\":\"/uploads/products/1754348251374-vwgx1e82mya.png\",\"link\":\"\",\"linkText\":\"\"}]}','2025-08-04 22:57:33','2025-08-04 22:57:33'),('9b68bcbf-c89e-11f0-9923-0637a5b9918d','1672d4cf-7606-11f0-9a75-0637a5b9918d','5b738254-70ca-11f0-9a55-0637a5b9918d',0,'{\"content\":\"<p>These are various projects that our customers have done themselves</p>\",\"textAlign\":\"left\"}','2025-11-23 18:59:58','2025-11-23 18:59:58'),('9b6f705c-c89e-11f0-9923-0637a5b9918d','1672d4cf-7606-11f0-9a75-0637a5b9918d','5b7382fa-70ca-11f0-9a55-0637a5b9918d',1,'{\"image\":\"/uploads/products/1754842969233-hlz5lsxceeq.jpg\",\"caption\":\"Solar Trailer\",\"alt\":\"\",\"size\":\"medium\"}','2025-11-23 18:59:58','2025-11-23 18:59:58'),('9b753fc3-c89e-11f0-9923-0637a5b9918d','1672d4cf-7606-11f0-9a75-0637a5b9918d','5b7382fa-70ca-11f0-9a55-0637a5b9918d',2,'{\"image\":\"/uploads/products/1755631874982-2mgx5cu0uh7.jpeg\",\"caption\":\"\",\"alt\":\"\",\"size\":\"medium\"}','2025-11-23 18:59:58','2025-11-23 18:59:58'),('9b7b53ef-c89e-11f0-9923-0637a5b9918d','1672d4cf-7606-11f0-9a75-0637a5b9918d','5b7382fa-70ca-11f0-9a55-0637a5b9918d',3,'{\"image\":\"/uploads/products/1755631867178-7d73vkjo6rl.jpeg\",\"caption\":\"\",\"alt\":\"\",\"size\":\"medium\"}','2025-11-23 18:59:58','2025-11-23 18:59:58'),('9b8136d4-c89e-11f0-9923-0637a5b9918d','1672d4cf-7606-11f0-9a75-0637a5b9918d','5b7382fa-70ca-11f0-9a55-0637a5b9918d',4,'{\"image\":\"/uploads/products/1755631858479-fco63lzu8sv.jpeg\",\"caption\":\"\",\"alt\":\"\",\"size\":\"medium\"}','2025-11-23 18:59:58','2025-11-23 18:59:58'),('9b871074-c89e-11f0-9923-0637a5b9918d','1672d4cf-7606-11f0-9a75-0637a5b9918d','5b7382fa-70ca-11f0-9a55-0637a5b9918d',5,'{\"image\":\"/uploads/products/1756652692282-51oxnwb4x88.jpg\",\"caption\":\"\",\"alt\":\"\",\"size\":\"medium\"}','2025-11-23 18:59:58','2025-11-23 18:59:58'),('9b8d7380-c89e-11f0-9923-0637a5b9918d','1672d4cf-7606-11f0-9a75-0637a5b9918d','5b7382fa-70ca-11f0-9a55-0637a5b9918d',6,'{\"image\":\"/uploads/products/1757043870291-890fawmc3rn.jpeg\",\"caption\":\"\",\"alt\":\"\",\"size\":\"medium\"}','2025-11-23 18:59:58','2025-11-23 18:59:58'),('9b93b1b9-c89e-11f0-9923-0637a5b9918d','1672d4cf-7606-11f0-9a75-0637a5b9918d','5b7382fa-70ca-11f0-9a55-0637a5b9918d',7,'{\"image\":\"/uploads/products/1759867087045-70stdynekbe.png\",\"caption\":\"EG4 Setup\",\"alt\":\"\",\"size\":\"medium\"}','2025-11-23 18:59:58','2025-11-23 18:59:58'),('9b9991e4-c89e-11f0-9923-0637a5b9918d','1672d4cf-7606-11f0-9a75-0637a5b9918d','5b738254-70ca-11f0-9a55-0637a5b9918d',8,'{\"content\":\"<p>Enter your text here...</p>\",\"textAlign\":\"left\"}','2025-11-23 18:59:58','2025-11-23 18:59:58'),('9b9f55b5-c89e-11f0-9923-0637a5b9918d','1672d4cf-7606-11f0-9a75-0637a5b9918d','5b7382fa-70ca-11f0-9a55-0637a5b9918d',9,'{\"image\":\"/uploads/products/1760360606658-rqmn46rm0ip.jpeg\",\"caption\":\"I saw your youtube video some years ago and it got me on the road to doing a solar panel system.  I originally got quoted $77,000 for a system less than half my size, but I was able to use your ideas to get my system done, it\'s 60 panels at 400 watts each, they\'re all bifacial, I was done for under $12,000 using your tips.  Anyway, so far it\'s produced a surplus of power for me and I use a lot of power.    I just really wanted to write you as I would not have done it without you, thank you for the video and encouraging words.  \",\"alt\":\"\",\"size\":\"medium\"}','2025-11-23 18:59:58','2025-11-23 18:59:58'),('9ba537bd-c89e-11f0-9923-0637a5b9918d','1672d4cf-7606-11f0-9a75-0637a5b9918d','5b7382fa-70ca-11f0-9a55-0637a5b9918d',10,'{\"image\":\"/uploads/products/1762742502526-xoserlwibga.jpeg\",\"caption\":\"\",\"alt\":\"\",\"size\":\"medium\"}','2025-11-23 18:59:59','2025-11-23 18:59:59'),('9bab7125-c89e-11f0-9923-0637a5b9918d','1672d4cf-7606-11f0-9a75-0637a5b9918d','5b7382fa-70ca-11f0-9a55-0637a5b9918d',11,'{\"image\":\"/uploads/products/1762742519310-76thbuvep2v.jpeg\",\"caption\":\"\",\"alt\":\"\",\"size\":\"medium\"}','2025-11-23 18:59:59','2025-11-23 18:59:59'),('9bb1393b-c89e-11f0-9923-0637a5b9918d','1672d4cf-7606-11f0-9a75-0637a5b9918d','5b7382fa-70ca-11f0-9a55-0637a5b9918d',12,'{\"image\":\"/uploads/products/1762742537565-st76ilpvz6s.jpeg\",\"caption\":\"\",\"alt\":\"\",\"size\":\"medium\"}','2025-11-23 18:59:59','2025-11-23 18:59:59'),('9bb6d192-c89e-11f0-9923-0637a5b9918d','1672d4cf-7606-11f0-9a75-0637a5b9918d','5b7382fa-70ca-11f0-9a55-0637a5b9918d',13,'{\"image\":\"/uploads/products/1762809778250-oje0uxmm5l.jpeg\",\"caption\":\"\",\"alt\":\"\",\"size\":\"medium\"}','2025-11-23 18:59:59','2025-11-23 18:59:59'),('9bbc381c-c89e-11f0-9923-0637a5b9918d','1672d4cf-7606-11f0-9a75-0637a5b9918d','5b7382fa-70ca-11f0-9a55-0637a5b9918d',14,'{\"image\":\"/uploads/products/1762809790121-mpqg4tmwu.jpeg\",\"caption\":\"\",\"alt\":\"\",\"size\":\"medium\"}','2025-11-23 18:59:59','2025-11-23 18:59:59'),('9bc1e9e7-c89e-11f0-9923-0637a5b9918d','1672d4cf-7606-11f0-9a75-0637a5b9918d','5b7382fa-70ca-11f0-9a55-0637a5b9918d',15,'{\"image\":\"/uploads/products/1762810316157-qdxihck9dji.jpeg\",\"caption\":\"\",\"alt\":\"\",\"size\":\"medium\"}','2025-11-23 18:59:59','2025-11-23 18:59:59'),('9bc7622b-c89e-11f0-9923-0637a5b9918d','1672d4cf-7606-11f0-9a75-0637a5b9918d','5b7382fa-70ca-11f0-9a55-0637a5b9918d',16,'{\"image\":\"/uploads/products/1763924394453-u6yvyk3c04.jpg\",\"caption\":\"\",\"alt\":\"\",\"size\":\"medium\"}','2025-11-23 18:59:59','2025-11-23 18:59:59'),('a7695eb9-7785-11f0-8e76-0637a5b9918d','43a6aae5-7065-11f0-9a55-0637a5b9918d','5b738021-70ca-11f0-9a55-0637a5b9918d',0,'{\"title\":\"\",\"subtitle\":\"Get guidance to understand how to do various tasks for your solar project\",\"columns\":3,\"cards\":[{\"title\":\"How To Install Solar Panels Yourself\",\"description\":\"Matt describes how he installed a 7KW solar panel system on his roof for $4,000 after tax credits, significantly reducing costs by doing it himself and avoiding professional installation fees.\",\"image\":\"/uploads/products/1754325341455-swsqmokcd1.png\",\"link\":\"\",\"linkText\":\"\"},{\"title\":\"How To Install Unistrut Racking System Yourself\",\"description\":\"Matt describes how he replaced his original treated lumber racking system with a Unistrut one, which are both much less expensive alternatives to a pre-built system.\",\"image\":\"/uploads/products/1754325434691-2bqi552o0uj.png\",\"link\":\"/how-to-install-unistrut-racking-system-yourself\",\"linkText\":\"\"},{\"title\":\"How To Make Decisions On Your Solar Project\",\"description\":\"This is an explanation of all the decisions you will need to make and helps guide you on those decisions.\",\"image\":\"/uploads/products/1754325438891-93h47ble2in.png\",\"link\":\"/how-to-make-decisions-on-your-solar-project\",\"linkText\":\"\"},{\"title\":\"How To Build A Ground Mount Solar System\",\"description\":\"This is an explanation of how to build a ground mount solar system, done by one of our customers.\",\"image\":\"/uploads/products/1754326359612-hnx537rr1mc.png\",\"link\":\"/how-to-build-a-ground-mount-solar-system\",\"linkText\":\"\"},{\"title\":\"How To Get Help On Your Solar Project\",\"description\":\"This is a list of resources for getting help on your project, whether you need help with design, permitting, installation, wiring, etc.\",\"image\":\"/uploads/products/1754326374899-uo2rvxqnvy8.png\",\"link\":\"/how-to-get-help-on-your-solar-project\",\"linkText\":\"\"},{\"title\":\"Customer Projects\",\"description\":\"Get inspiration about your project from some of the projects our customers have done!\",\"image\":\"/uploads/products/1754843097698-8bg04l22y78.jpg\",\"link\":\"/customer-projects\",\"linkText\":\"\"}]}','2025-08-12 14:07:17','2025-08-12 14:07:17'),('ed15f33a-7780-11f0-8e76-0637a5b9918d','320279c6-7172-11f0-9a85-0637a5b9918d','5b7382fa-70ca-11f0-9a55-0637a5b9918d',0,'{\"image\":\"/uploads/products/1754347740945-urku0wup97.png\",\"caption\":\"\",\"alt\":\"\",\"size\":\"medium\"}','2025-08-12 13:33:26','2025-08-12 13:33:26'),('ed1cfcfe-7780-11f0-8e76-0637a5b9918d','320279c6-7172-11f0-9a85-0637a5b9918d','5b738254-70ca-11f0-9a55-0637a5b9918d',1,'{\"content\":\"<p>Welcome to our new website and blog!&nbsp; We plan to keep you updated on the latest in solar and keep you informed.</p>\",\"textAlign\":\"left\"}','2025-08-12 13:33:26','2025-08-12 13:33:26');
