--
-- Table structure for table `product_listings`
--

DROP TABLE IF EXISTS `product_listings`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `product_listings` (
  `id` varchar(36) NOT NULL DEFAULT uuid(),
  `product_id` varchar(36) NOT NULL,
  `platform_id` varchar(36) NOT NULL,
  `template_id` varchar(36) DEFAULT NULL,
  `external_listing_id` varchar(255) DEFAULT NULL,
  `title` varchar(500) DEFAULT NULL,
  `description` text DEFAULT NULL,
  `price` decimal(10,2) DEFAULT NULL,
  `status` enum('draft','pending','active','paused','ended','error') DEFAULT 'draft',
  `listing_url` varchar(1000) DEFAULT NULL,
  `error_message` text DEFAULT NULL,
  `last_sync_at` timestamp NULL DEFAULT NULL,
  `auto_sync` tinyint(1) DEFAULT 1,
  `created_at` timestamp NULL DEFAULT current_timestamp(),
  `updated_at` timestamp NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  PRIMARY KEY (`id`),
  UNIQUE KEY `unique_product_platform` (`product_id`,`platform_id`),
  KEY `platform_id` (`platform_id`),
  KEY `template_id` (`template_id`),
  CONSTRAINT `product_listings_ibfk_1` FOREIGN KEY (`product_id`) REFERENCES `products` (`id`) ON DELETE CASCADE,
  CONSTRAINT `product_listings_ibfk_2` FOREIGN KEY (`platform_id`) REFERENCES `listing_platforms` (`id`) ON DELETE CASCADE,
  CONSTRAINT `product_listings_ibfk_3` FOREIGN KEY (`template_id`) REFERENCES `listing_templates` (`id`) ON DELETE SET NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

--
-- Dumping data for table `product_listings`
--

LOCK TABLES `product_listings` WRITE;
/*!40000 ALTER TABLE `product_listings` DISABLE KEYS */;
INSERT INTO `product_listings` VALUES ('21ec3b1a-53dd-11f0-8d93-0637a5b9918d','25c67a2e-52ca-11f0-bbc5-06479488ad4b','ksl-platform-id','ksl-default-template','ksl_1751086967049','APsystems DS3-L Dual Microinverter - DS3-L-NA-768VA','APsystems DS3-L Dual Microinverter\n\nSKU: DS3-L-NA-768VA\nPrice: $180.00\n\nDual-module // Single phase // 3rd generationAPsystems\' 3rd generation of dual-module, single-phase microinverters, the DS3 product family represents the culmination of years of power conversion expertise and innovation in high-efficiency, high-density power conversion to maximize the peak performance of today\'s high-capacity PV modules.The DS3 series reaches unprecedented levels of power output and is fully backwards compatible with QS1 and YC600 microinverters and accessories. It features 2 input channels, each with independent MPPT, and encrypted wireless Zigbee communication. An innovative and compact design makes the product lighter while maximizing power production, and silicone-encapsulated components reduce stress on electronics, facilitate thermal dissipation, and enhance weatherproofing. Reliability is significantly increased thanks to 20% fewer components than previous generations.The DS3 series is grid-interactive and fully compliant with CA Rule 21 requirements. With its unparalleled performance, efficiency of 97%, and increased reliability, the APsystems DS3 series is a gamechanger for residential and commercial solar.Product ModelsDS3-S - 640VA output, ideal for PV modules up to 400W+DS3-L - 748VA output, ideal for PV modules up to 480W+DS3 - 880VA output, ideal for PV modules up to 550W+(+ means higher wattage PV modules will not negatively impact the inverter)A Class ApartWhat is so unique about these new microinverters? The DS3 series utilizes a new architecture that can manage far higher capacities of PV modules than conventional 1:1 microinverters.The DS3-S and DS3-L have also been specifically designed to maximize the output on each residential circuit. Compared with competing devices, the DS3-S has up to 37% more AC output and the DS3-L up to 60% more output power per channel than conventional microinverters. For many installers around the world, the new DS3 series has become a strong competitive advantage helping them save money while winning more business.Key FeaturesSingle-Phase, Dual-Module Microinverter640W, 768W, And 880W ModelsDual, Independent MpptEncrypted Zigbee WirelessAccommodates 2 Pv Modules Up To 550Wp (Ds3 Model)Certified To Ul1741 Sa (Ca Rule 21) StandardCompatible With Qs1 &amp; Yc600 Products &amp; Accessories\n\nCondition: New\nLocal pickup or delivery available in Utah area\nCall or text for more information!',180.00,'active','https://classifieds.ksl.com/listing/ksl_1751086967049',NULL,'2025-06-28 05:03:36',1,'2025-06-28 05:02:47','2025-06-28 05:03:36'),('3a691c4c-51f4-11f0-bbc5-06479488ad4b','6782421e-4e6f-11f0-bbc5-06479488ad4b','facebook-platform-id','facebook-default-template','10096378057114463','Alexus 405 Watt Black Bifacial Solar Panel - ALEX-405-B54-S','Alexus 405 Watt Black Bifacial Solar Panel\n\nSKU: ALEX-405-B54-S\nPrice: $105.00\n\nAmong the newest offerings of Alexus Solar, ALEX-405-B-54-S is part of the ALEX-390~410-B-54-S series. These panels use state-of-the-art technology to achieve high efficiency and dependability. The Passivated Emitter Rear Contact (PERC) technology ensures excellent power output. This solar cell type employs an additional reflective layer to absorb more sunlight.Half-cut cell technology adds a few more percent to the overall performance, making this model a great example of efficiency. Alexus Solar made solar cells in ALEX-405-B-54-S two times smaller than the standard size, thus reducing power loss and improving low-light behavior. As a result, the panel achieves an impressive efficiency of 20.7%. Novel design solutions allow this panel to look as well as it performs. This model is just 1.2\" in depth and is jet black with a sleek finish. The panel\'s functionality and durability are not affected by its aesthetic appeal though. Alexus Solar provides 25 years of product warranty and guarantees that after 25 years, performance will be at 85.04% or more.405 W power output108 half-cut PERC cells20.7% efficiency1500 V DC maximum system voltageMC4 compatible connectors25-year product and 25-year performance warranties\n\nCondition: New\nPickup or delivery available\nMessage for more details!',105.00,'active','https://www.facebook.com/marketplace/item/10096378057114463',NULL,'2025-06-25 18:44:20',1,'2025-06-25 18:43:04','2025-06-25 18:44:20'),('3c35c8b8-51eb-11f0-bbc5-06479488ad4b','328f5187-4d17-11f0-bbc5-06479488ad4b','facebook-platform-id','facebook-default-template','10033822650004845','Growatt 3.3KWH Solar Lithium Battery - ML33RTA','Growatt 3.3KWH Solar Lithium Battery\n\nSKU: ML33RTA\nPrice: $680.00\n\nPoweramp Growatt 3.3KWH Solar Battery ML33RTA 51.2V IP20 UN3480 4G/Y40/S/21\n\nCondition: New\nPickup or delivery available\nMessage for more details!',680.00,'active','https://www.facebook.com/marketplace/item/10033822650004845',NULL,'2025-06-27 19:48:53',1,'2025-06-25 17:38:41','2025-06-27 19:48:53'),('3d41b777-51c4-11f0-bbc5-06479488ad4b','c6b303ea-4eb5-11f0-bbc5-06479488ad4b','facebook-platform-id','facebook-default-template','23972212709131904','Tigo 11.4 kWh Inverter - TSI-11.4K-US','Tigo 11.4 kWh Inverter\n\nSKU: TSI-11.4K-US\nPrice: $900.00\n\nTigo TSI-11.4K-US 11.4kW Energy Storage Hybrid Inverter\n\nCondition: New\nPickup or delivery available\nMessage for more details!',900.00,'ended','https://www.facebook.com/marketplace/item/23972212709131904',NULL,'2025-06-25 18:45:33',1,'2025-06-25 12:59:33','2025-06-25 18:45:33'),('a4c31829-527e-11f0-bbc5-06479488ad4b','c0a4e674-51f9-11f0-bbc5-06479488ad4b','facebook-platform-id','facebook-default-template','24295339266759022','JA Solar 255 Watt Solar Panel - JAP6 60/255/3BB','JA Solar 255 Watt Solar Panel\n\nSKU: JAP6 60/255/3BB\nPrice: $50.00\n\nHarness the power of the sun with the JAP6 60/255/3BB, a high-performance polycrystalline solar panel designed for residential, commercial, and utility-scale solar projects.Key Features:Powerful Output: This 255-watt panel boasts a high output and a 15.59% conversion efficiency, meaning it\'s designed to generate significant power for your energy needs. It\'s a great option for rooftop or ground mount applications.Built to Last: The JAP6 60/255/3BB is built for durability and reliability. It\'s certified to withstand high wind loads (2400Pa) and snow loads (5400Pa), making it a robust choice for various weather conditions. It\'s also designed with high salt and ammonia resistance.Reliable Quality: JA Solar is a world-leading manufacturer of high-performance photovoltaic products. The JAP6 60/255/3BB demonstrates this commitment to quality with features like:Positive power tolerance (0~+5W)100% EL double-inspection ensuring defect-free modules.Comprehensive Certifications: This panel is certified by various international standards, including IEC 61215, IEC 61730, and UL1703.Superior Warranty: Enjoy peace of mind with a 10-year product warranty and a 25-year linear power output warranty. This warranty guarantees 97.5% of its original output after 25 years.Low Light Performance: Designed to offer outstanding performance in low-light environments.Clear Anodized Frame: Features a clear anodized frame for a clean aesthetic.MC4 Connector: Equipped with a standard MC4 connector for easy installation.Please note: The JAP6 60/255/3BB model is no longer available.Product Specifications:Watts (Pmax): 255 WDimensions: 64.96\" x 39.02\" x 1.57\"Weight: 40.12 lbsMax Power Voltage (VMPP): 30.29 VMax Power Current (IMPP): 8.42 AOpen Circuit Voltage (VOC): 37.82 VShort Circuit Current (ISC): 8.98 AMax System Voltage: DC 1000 VCell Type: PolycrystallineConsider this reliable and efficient solar panel for your renewable energy needs!\n\nCondition: New\nPickup or delivery available\nMessage for more details!',50.00,'active','https://www.facebook.com/marketplace/item/24295339266759022',NULL,NULL,1,'2025-06-26 11:13:53','2025-06-26 11:13:53'),('bb442470-51fb-11f0-bbc5-06479488ad4b','c0f1f5bf-4c0b-11f0-bbc5-06479488ad4b','facebook-platform-id','facebook-default-template','24749332278001123','EG4 WallMount All Weather Lithium Battery 14.3 kWh - WP-16/280-1AWLL','EG4 WallMount All Weather Lithium Battery 14.3 kWh\n\nSKU: WP-16/280-1AWLL\nPrice: $3800.00\n\nEG4 WallMount All Weather Lithium Battery | 48V 280Ah | 14.3kWh LiFePO4 | All-Weather Energy Storage | UL1973, UL9540A | 10-Year WarrantyIntroducing the EG4 WallMount All Weather Battery - the ultimate energy storage solution for all your solar power needs. This cutting-edge 48V 280Ah Lithium Iron Phosphate (LiFePO4) battery redefines reliability and performance, ensuring your power supply remains uninterrupted.Key Features:Confident Power10kW delivery, with peak power 10.5kW (10 sec.) &amp; 15.4kW (3 sec.)Constant discharge current – 200AOver 8000 cycles at 80% DOD with an 82.6Mwh lifetime productionReliableSmart and intelligent BMS for reliability, efficiency and safetyIntegrated self-heating features when needed in low temperatureAll-Weather DesignPerfect for outdoor applications, built to withstand various weather conditionsIntegrated self-heating feature ensures optimal battery performance in low temperatures.Weather rated quick connectors (Amphenol)SafetyDual onboard fire arrestors offer fail-safe protectionInnovative total emergency stop function for instant shutdown by RSD / ESS disconnect / inverter RSD10-year warranty offered by EG4 Electronics.Seamless IntegrationCan pair with any  hybrid or off-grid inverter in the marketDesigned to pair seamlessly with EG4, Victron, Growatt,Megarevo, Luxpower, Deye, and Sol-Ark invertersOnboard LCD touch screen for easy BMS monitoring and communication.Quick connect battery cables for fast, safe, and reliable battery connections.Comprehensive CertificationsUL9540A Certified, UL1973UL9540 with 18kPV: for PowerPro ESSCN: 5026744Outdoor Rating IP65Energy Storage SystemOptional conduit box addon makes installation with an EG4 18kPV simpleTurn any EG4 All Weather Battery into a fully capable Energy Storage System when paired with an EG4 18kPVNo thermal monitoring, or ventilation neededNo maintenanceTechnical Specifications:Model name: WallMount AllWeather BatteryBattery Type: LiFePO4 (Lithium Iron Phosphate, Grade A)Voltage: 48V (Nominal: 51.2V, Float: 54V)Continuous Charge/Discharge Current: 200A (Max)Capacity: 14.3kWhBMS: 200AWeight: 308.6 lbs. / 140Kg\n\nCondition: New\nPickup or delivery available\nMessage for more details!',3800.00,'active','https://www.facebook.com/marketplace/item/24749332278001123',NULL,'2025-06-26 11:18:04',1,'2025-06-25 19:36:46','2025-06-26 11:18:04'),('d0bd4393-51f4-11f0-bbc5-06479488ad4b','3364d48f-5124-11f0-bbc5-06479488ad4b','facebook-platform-id','facebook-default-template','24144006828556328','EG4 WallMount Indoor Battery 14.3kWh - WM-48-280-1-IN-LL-00','EG4 WallMount Indoor Battery 14.3kWh\n\nSKU: WM-48-280-1-IN-LL-00\nPrice: $3400.00\n\nEG4-WallMount Indoor Battery | 48V 280Ah | 14.3kWh | Indoor | Heated UL1973, UL9540A | 10-Year WarrantyThe WallMount Indoor 14.3kWh batteries are ideal for low-voltage residential indoor energy storage applications. The batteries use lithium iron phosphate cells with the highest safety performance and an intelligent Battery Management System (BMS) that can monitor and record the voltage of each cell along with the current, voltage, and temperature of the module in real-time. The BMS also contains a passive balance function and an advanced battery control method, both of which improve the performance of the battery pack.Key Features:ON-BOARD LCD TOUCH SCREENEasy to see BMS monitoring, and selectable closed-loop communications with EG4, Schneider, Sol-Ark, Victron, Growatt, Megarevo, Luxpower, and Deye inverters.DUAL ON-BOARD FIRE ARRESTORSOffer fail-safe protection against thermal runaway.INTEGRATED SELF-HEATING FEATUREInternal heating keeps cells operating during cold temperatures.INTEGRATED BUSBARSThe battery design comes manufactured with 600A internal busbars with multiple terminals (4 positive &amp; 4 negative) eliminating the need for external busbars when paralleling batteries and/or multiple inverters.INNOVATIVE EMERGENCY STOP FUNCTIONThe optional ESS disconnect can shut down all batteries and inverters (if equipped with rapid shut down capability) with the press of a button.THE PERFECT PARTNER TO EG4 INVERTERSThe optional conduit box mates up directly to the connection ports of EG4 inverters allowing a sleek and efficient installation. For other inverters or stand-alone battery installation, the conduit box plugs should be installed.Module Operating ParametersVoltage: 51.2VTotal Energy Capacity: 14.3kWhCapacity: 280AhCharging Voltage (Bulk/Absorb): 56.0V (+/-0.8V) to 56.2V (+/-0.2V)Float Voltage: 54V (+/-0.2V)Low DC Cutoff: 44.8V (adjustable start from 47V to 45.6V)Charging Current: Up to 200A (continuous), recommended range: 60A - 160ADischarging Current: Up to 200A (continuous), recommended: 160AEnvironmental ParametersCharging Range: 32°F to ≈113°F (0°C to ≈45°C)Discharging Range: -4°F to ≈122°F (-20°C to ≈50°C)Storage Range: -4°F to ≈122°F (-20°C to ≈50°C)Ingress Protection: IP20Charging/Discharging ProtectionOvercharging Protection: &gt;205A (10 sec), &gt;225A (3 sec)Temperature Protection: &lt;23°F or &gt;158°F (1 sec), &lt;-5°C or &gt;70°C (1 sec)General SpecificationsCommunication Ports: RS485/CAN Can be customizedCycle Life: &gt;8000 Cycles, 80% Depth of Discharge (DOD)Design Life: Over 15 YearsWeight: 282.2 lbs. (128 kg)Safety Certifications: UL1973, UL 9540A (Testing)\n\nCondition: New\nPickup or delivery available\nMessage for more details!',3400.00,'active','https://www.facebook.com/marketplace/item/24144006828556328',NULL,'2025-06-25 19:36:01',1,'2025-06-25 18:47:16','2025-06-25 19:36:01'),('db019348-51f4-11f0-bbc5-06479488ad4b','09c6d505-4cb3-11f0-bbc5-06479488ad4b','facebook-platform-id','facebook-default-template','10030388773744715','EG4 6000XP Off-Grid Inverter - EG4-6000XP','EG4 6000XP Off-Grid Inverter\n\nSKU: EG4-6000XP\nPrice: $1900.00\n\nEG4 6000XP Off-Grid Inverter | 8000W PV Input | 6000W Output | 480V VOC Input | 48V 120/240V Split Phase | All-In-One Solar InverterKey Features:The EG4 6000XP is a cutting-edge 48V split-phase, off-grid inverter and charger, designed to revolutionize your energy needs. With an impressive 8kW of PV input capacity and an efficient 6kW continuous power output, it also serves as a battery 140A charger. What sets it apart is its scalability - you can parallel up to 16 units for an impressive 96kWs of output power while controlling multiple stations and units seamlessly using our advanced EG4 monitoring software.Performance Components6000W rated output powerParallel up to 16 units for 96kWs of output powerBuilt-in Switchgear for reduced installation costs and enhanced safetySave up to $300 with built-in breakers, disconnects and more!Transformer-Free DesignDedicated Generator ConnectionInverter, AC Charger, and Solar Charge ControllerAll-In-OneEverything needed to get startedSimple to install, easy to manageManages power from energy storage systems, and grid simultaneously120/240V split phaseEfficiencyMPPT Efficiency 99%Outperforms similar-sized competitors by an average of 7%Battery Charging Efficiency 93%Battery Discharging Efficiency 93%50W Idle Consumption (with battery)MonitoringEG4 Monitoring AppGoogle PlayApp StoreWi-Fi/4G/LANRS485Comprehensive CertificationsUL 1741Ingress Protection Rating: IP20\n\nCondition: New\nPickup or delivery available\nMessage for more details!',1900.00,'active','https://www.facebook.com/marketplace/item/10030388773744715',NULL,'2025-06-25 18:49:42',1,'2025-06-25 18:47:33','2025-06-25 18:49:42'),('de72c11f-51fa-11f0-bbc5-06479488ad4b','77c0ad41-51f8-11f0-bbc5-06479488ad4b','facebook-platform-id','facebook-default-template','24920555294240064','Sunpower 425 Watt Solar Panel - SPR-M425-H-AC','Sunpower 425 Watt Solar Panel\n\nSKU: SPR-M425-H-AC\nPrice: $90.00\n\nMonocrystalline solar cell technology for enhanced efficiencyProduces 20.4W per square feet to optimize larger roof spacesIndependently generates renewable energy for electric bill savings\n\nCondition: New\nPickup or delivery available\nMessage for more details!',90.00,'active','https://www.facebook.com/marketplace/item/24920555294240064',NULL,NULL,1,'2025-06-25 19:30:36','2025-06-25 19:30:36'),('fc221cc4-51c3-11f0-bbc5-06479488ad4b','1cbfb4ac-4abe-11f0-bbc5-06479488ad4b','facebook-platform-id','facebook-default-template','9348589751908822','Mixed Black 300 (43) - AUTO-1750084083504-1SVAF','Mixed Black 300 (43)\n\nSKU: AUTO-1750084083504-1SVAF\nPrice: $46.67\n\nAuto-created product from order import\n\nCondition: New\nPickup or delivery available\nMessage for more details!',46.67,'ended','https://www.facebook.com/marketplace/item/9348589751908822',NULL,'2025-06-25 12:58:33',1,'2025-06-25 12:57:43','2025-06-25 12:58:33');
