INSERT INTO `products` VALUES ('02129285-6cb8-11f0-9be2-0637a5b9918d','Sunpower 425 Watt Solar Panel','<p>Monocrystalline solar cell technology for enhanced efficiency</p><p>Produces 20.4W per square feet to optimize larger roof spaces</p><p>Independently generates renewable energy for electric bill savings</p><p>We can ship these to the Wasatch front in Utah for $100-150 for any quantity.  Any other destination in the US (other than Alaska and Hawaii) is about $400-700 for each pallet of 21.  </p>',70.00,NULL,'/uploads/datasheets/1760108321501-afghae6xdua.pdf','a0b3eb1a-4e72-11f0-bbc5-06479488ad4b','sunpower-425',0.00,'[{\"type\":\"fixed\",\"name\":\"Standard Shipping\",\"description\":\"7-10 business days\",\"cost\":60},{\"type\":\"local_pickup\",\"name\":\"Local Pickup\",\"description\":\"Pick up from our location\",\"warehouse_ids\":[\"main-warehouse-id\",\"41ee39d4-51d5-11f0-bbc5-06479488ad4b\",\"east-warehouse-id\"]}]',0,'calculated',0.00,'sunpower-425-watt-solar-panel-sunpower-425',1,'2025-07-29 20:10:01','2025-12-04 16:16:46'),('039fc4b8-52c9-11f0-bbc5-06479488ad4b','APsystems DS3-S Dual Microinverter 640VA','<p><strong>Dual-module // Single phase // 3rd generation</strong><br><br>APsystems\' 3rd generation of dual-module, single-phase microinverters, the DS3 product family represents the culmination of years of power conversion expertise and innovation in high-efficiency, high-density power conversion to maximize the peak performance of today\'s high-capacity PV modules.<br><br>The DS3 series reaches unprecedented levels of power output and is fully backwards compatible with QS1 and YC600 microinverters and accessories. It features 2 input channels, each with independent MPPT, and encrypted wireless Zigbee communication. An innovative and compact design makes the product lighter while maximizing power production, and silicone-encapsulated components reduce stress on electronics, facilitate thermal dissipation, and enhance weatherproofing. Reliability is significantly increased thanks to 20% fewer components than previous generations.<br><br>The DS3 series is grid-interactive and fully compliant with CA Rule 21 requirements. With its unparalleled performance, efficiency of 97%, and increased reliability, the APsystems DS3 series is a gamechanger for residential and commercial solar.<br><br><strong>Product Models</strong></p><ul><li><p>DS3-S - 640VA output, ideal for PV modules up to 400W+</p></li><li><p>DS3-L - 748VA output, ideal for PV modules up to 480W+</p></li><li><p>DS3 - 880VA output, ideal for PV modules up to 550W+</p></li><li><p>(+ means higher wattage PV modules will not negatively impact the inverter)</p></li></ul><p><strong>A Class Apart</strong><br>What is so unique about these new microinverters? The DS3 series utilizes a new architecture that can manage far higher capacities of PV modules than conventional 1:1 microinverters.<br><br>The DS3-S and DS3-L have also been specifically designed to maximize the output on each residential circuit. Compared with competing devices, the DS3-S has up to 37% more AC output and the DS3-L up to 60% more output power per channel than conventional microinverters. For many installers around the world, the new DS3 series has become a strong competitive advantage helping them save money while winning more business.<br><br><strong>Key Features</strong></p><ul><li><p>Single-Phase, Dual-Module Microinverter</p></li><li><p>640W, 768W, And 880W Models</p></li><li><p>Dual, Independent Mppt</p></li><li><p>Encrypted Zigbee Wireless</p></li><li><p>Accommodates 2 Pv Modules Up To 550Wp (Ds3 Model)</p></li><li><p>Certified To Ul1741 Sa (Ca Rule 21) Standard</p></li><li><p>Compatible With Qs1 &amp; Yc600 Products &amp; Accessories</p></li></ul>',170.00,NULL,'/uploads/datasheets/1750968364741-wp6n3a1k6b.pdf','b5ef143e-4e72-11f0-bbc5-06479488ad4b','DS3-S-NA-640VA',0.00,'[]',0,'calculated',0.00,'apsystems-ds3-s-dual-microinverter-640va-ds3-s-na-640va',1,'2025-06-26 20:06:15','2025-07-14 19:04:24'),('03ec7d15-63ce-11f0-8e60-0637a5b9918d','Revive 250 Watt Solar Panel','<p>They are 240W - 270W most of them are Canadian Solar but others are Trina Solar.</p><p>Invoice #RL-25.07.17-05</p><p>July 17, 2025</p><p><strong>Canadian Solar CS6P-255P</strong></p><p>$17,226.00</p><p>($9.00 ea.) × 1,914</p><p><strong>Canadian Solar CS6X-280P</strong></p><p>$3,834.00</p><p>($9.00 ea.) × 426</p><p><strong>Trina Solar TSM-285PA14</strong></p><p>$810.00</p><p>($9.00 ea.) × 90</p><p><strong>Shipping</strong></p><p>$11,400.00</p><p>($3,800.00 ea.) × 3</p><p><strong>Subtotal</strong></p><p>$33,270.00</p><p><strong>Sales Tax (8.41%)</strong></p><p>$2,798.01</p>',50.00,NULL,NULL,'a0b3eb1a-4e72-11f0-bbc5-06479488ad4b','revive-250',0.00,'[]',0,'calculated',0.00,'revive-250-watt-solar-panel-revive-250',1,'2025-07-18 11:54:52','2025-12-13 22:33:14'),('0483afb3-4d17-11f0-bbc5-06479488ad4b','Growatt ARO HV 6.6 kWh Battery System','<p>This is for the cabinet only. You will likely want to also purchase two of the 3.3 kWh batteries at</p><p></p><p><a target=\"_blank\" rel=\"noopener noreferrer nofollow\" class=\"text-blue-600 underline\" href=\"https://payoffsolar.com/product/growatt-33kwh-solar-lithium-battery-ml33rta\">https://payoffsolar.com/product/growatt-33kwh-solar-lithium-battery-ml33rta</a></p><p></p><p>The Growatt ARO HV 6.6 kWh Battery System is a lithium iron phosphate (LiFePO4) battery designed for residential use with Growatt hybrid inverters. It offers a 6.6 kWh capacity, with 5.94 kWh usable, and is compatible with Growatt MIN-XH series battery-ready inverters. The system is designed for safety and reliability with features like a long cycle life, compatibility with various Growatt inverters, and certifications like UL1973 and IP65.</p>',400.00,NULL,'/uploads/datasheets/1750869561074-j9tgdwglbf.pdf','a98c7b21-4e72-11f0-bbc5-06479488ad4b','ARO66',0.00,'[]',0,'calculated',0.00,'growatt-aro-hv-66-kwh-battery-system-aro66',1,'2025-06-19 14:09:30','2025-10-29 19:30:37'),('088c1fd6-d0a5-11f0-9923-0637a5b9918d','Meyer Burger White 390 Watt Solar Panel','<p>The Meyer Burger 390W solar panel is <strong>a high-efficiency, monocrystalline module with a 390W power output and a 21.2% efficiency rate</strong>. It features advanced <a target=\"_blank\" rel=\"noopener noreferrer nofollow\" class=\"text-blue-600 underline GI370e\" href=\"https://www.google.com/search?q=Heterojunction+%28HJT%29+technology&amp;sca_esv=8dfe9edb86176f37&amp;rlz=1C5GCEM_enUS1118US1118&amp;sxsrf=AE3TifMRhg4SqczUzi745_TtS16_lWtc8Q%3A1764806740113&amp;ei=VNAwaaPUBsGWkPIPh7L34Ag&amp;ved=2ahUKEwj87L2-0aKRAxWal-4BHfb3N9kQgK4QegQIARAE&amp;uact=5&amp;oq=meyer+burger+solar+panel+390+description&amp;gs_lp=Egxnd3Mtd2l6LXNlcnAiKG1leWVyIGJ1cmdlciBzb2xhciBwYW5lbCAzOTAgZGVzY3JpcHRpb24yBRAhGKABMgUQIRigATIFECEYoAEyBRAhGKABMgUQIRigAUjTIlCeA1i_IXAEeACQAQCYAWSgAbQMqgEEMTkuMbgBA8gBAPgBAZgCF6ACvQzCAgcQIxiwAxgnwgIKEAAYsAMY1gQYR8ICBhAAGBYYHsICCBAAGBYYChgewgILEAAYgAQYhgMYigXCAggQABiABBiiBMICBRAhGKsCmAMAiAYBkAYJkgcEMjIuMaAH6WCyBwQxOC4xuAe1DMIHBjguMTQuMcgHIA&amp;sclient=gws-wiz-serp&amp;mstk=AUtExfCXtTM39lecdlqmI1sirDOQ3dGN7tWsncR29q-1PaAjesFmzFFyyUuwy5fDptNtF71KJ4yl40qMfa8KBh03-nDT9nFZSYPQVju6Xu1Wjitj0aPm1ueNICffBWgMIGdZRlRQIe6iILgi0XpKePgS13srhXytgVJe2--L85qXqqmLMDqekfv7hemKecYaAb5Xs9-j-MOFAVB_qIQgGGjHHKANpWfg_hEaipSmNDEqR1gmx4RIfZRfhDIvm75DOr_Q8lPLjQy3eE1rDXuqw8nLZPrW&amp;csui=3\">Heterojunction (HJT) technology</a> and <a target=\"_blank\" rel=\"noopener noreferrer nofollow\" class=\"text-blue-600 underline GI370e\" href=\"https://www.google.com/search?q=half-cut+cells&amp;sca_esv=8dfe9edb86176f37&amp;rlz=1C5GCEM_enUS1118US1118&amp;sxsrf=AE3TifMRhg4SqczUzi745_TtS16_lWtc8Q%3A1764806740113&amp;ei=VNAwaaPUBsGWkPIPh7L34Ag&amp;ved=2ahUKEwj87L2-0aKRAxWal-4BHfb3N9kQgK4QegQIARAF&amp;uact=5&amp;oq=meyer+burger+solar+panel+390+description&amp;gs_lp=Egxnd3Mtd2l6LXNlcnAiKG1leWVyIGJ1cmdlciBzb2xhciBwYW5lbCAzOTAgZGVzY3JpcHRpb24yBRAhGKABMgUQIRigATIFECEYoAEyBRAhGKABMgUQIRigAUjTIlCeA1i_IXAEeACQAQCYAWSgAbQMqgEEMTkuMbgBA8gBAPgBAZgCF6ACvQzCAgcQIxiwAxgnwgIKEAAYsAMY1gQYR8ICBhAAGBYYHsICCBAAGBYYChgewgILEAAYgAQYhgMYigXCAggQABiABBiiBMICBRAhGKsCmAMAiAYBkAYJkgcEMjIuMaAH6WCyBwQxOC4xuAe1DMIHBjguMTQuMcgHIA&amp;sclient=gws-wiz-serp&amp;mstk=AUtExfCXtTM39lecdlqmI1sirDOQ3dGN7tWsncR29q-1PaAjesFmzFFyyUuwy5fDptNtF71KJ4yl40qMfa8KBh03-nDT9nFZSYPQVju6Xu1Wjitj0aPm1ueNICffBWgMIGdZRlRQIe6iILgi0XpKePgS13srhXytgVJe2--L85qXqqmLMDqekfv7hemKecYaAb5Xs9-j-MOFAVB_qIQgGGjHHKANpWfg_hEaipSmNDEqR1gmx4RIfZRfhDIvm75DOr_Q8lPLjQy3eE1rDXuqw8nLZPrW&amp;csui=3\">half-cut cells</a> for superior performance in varying light conditions, enhanced durability, and a low-degradation rate. The panel is also noted for its sleek, black-on-black aesthetic, making it suitable for residential use, and comes with a 25-year product and performance warranty.&nbsp;</p><p><strong>Key features</strong></p><ul><li><p><strong>Power and efficiency:</strong> 390W power output with 21.2% efficiency.</p></li><li><p><strong>Cell technology:</strong> 120 half-cut, n-type HJT cells that combine monocrystalline and amorphous silicon layers to improve light absorption and reduce energy loss.</p></li><li><p><strong>Performance:</strong> Superior performance in low-light conditions and a lower degradation rate compared to conventional panels, with only a 7-8% power loss after 25 years.</p></li><li><p><strong>Durability:</strong> Robust design with high snow and wind load ratings (5400 Pa snow, 2400 Pa wind, though some sources list higher limits like 6000 Pa / 4000 Pa) and resistance to salt mist and PID.</p></li><li><p><strong>Technology:</strong> Incorporates <a target=\"_blank\" rel=\"noopener noreferrer nofollow\" class=\"text-blue-600 underline GI370e\" href=\"https://www.google.com/search?q=SmartWire+Connection+Technology+%28SWCT%29&amp;sca_esv=8dfe9edb86176f37&amp;rlz=1C5GCEM_enUS1118US1118&amp;sxsrf=AE3TifMRhg4SqczUzi745_TtS16_lWtc8Q%3A1764806740113&amp;ei=VNAwaaPUBsGWkPIPh7L34Ag&amp;ved=2ahUKEwj87L2-0aKRAxWal-4BHfb3N9kQgK4QegQIBBAF&amp;uact=5&amp;oq=meyer+burger+solar+panel+390+description&amp;gs_lp=Egxnd3Mtd2l6LXNlcnAiKG1leWVyIGJ1cmdlciBzb2xhciBwYW5lbCAzOTAgZGVzY3JpcHRpb24yBRAhGKABMgUQIRigATIFECEYoAEyBRAhGKABMgUQIRigAUjTIlCeA1i_IXAEeACQAQCYAWSgAbQMqgEEMTkuMbgBA8gBAPgBAZgCF6ACvQzCAgcQIxiwAxgnwgIKEAAYsAMY1gQYR8ICBhAAGBYYHsICCBAAGBYYChgewgILEAAYgAQYhgMYigXCAggQABiABBiiBMICBRAhGKsCmAMAiAYBkAYJkgcEMjIuMaAH6WCyBwQxOC4xuAe1DMIHBjguMTQuMcgHIA&amp;sclient=gws-wiz-serp&amp;mstk=AUtExfCXtTM39lecdlqmI1sirDOQ3dGN7tWsncR29q-1PaAjesFmzFFyyUuwy5fDptNtF71KJ4yl40qMfa8KBh03-nDT9nFZSYPQVju6Xu1Wjitj0aPm1ueNICffBWgMIGdZRlRQIe6iILgi0XpKePgS13srhXytgVJe2--L85qXqqmLMDqekfv7hemKecYaAb5Xs9-j-MOFAVB_qIQgGGjHHKANpWfg_hEaipSmNDEqR1gmx4RIfZRfhDIvm75DOr_Q8lPLjQy3eE1rDXuqw8nLZPrW&amp;csui=3\">SmartWire Connection Technology (SWCT)</a> for improved stability and breakage resistance.</p></li><li><p><strong>Aesthetics:</strong> Elegant, black-on-black design suitable for residential installations.</p></li><li><p><strong>Warranty:</strong> 25-year product warranty and a 25-year performance warranty.</p></li><li><p><strong>Dimensions:</strong> 1767 mm (Length) x 1041 mm (Width) x 35 mm (Depth).&nbsp;</p></li></ul>',95.00,NULL,'/uploads/datasheets/1764806730509-qyxzf0akru.pdf','a0b3eb1a-4e72-11f0-bbc5-06479488ad4b','MB_W120AyB_390',0.00,'[]',0,'calculated',0.00,'meyer-burger-white-390-watt-solar-panel-mbw120ayb390',1,'2025-12-04 00:06:08','2025-12-04 00:06:08'),('09c6d505-4cb3-11f0-bbc5-06479488ad4b','EG4 6000XP Off-Grid Inverter','<h1><strong>EG4 6000XP Off-Grid Inverter | 8000W PV Input | 6000W Output | 480V VOC Input | 48V 120/240V Split Phase | All-In-One Solar Inverter</strong></h1><p><strong>Key Features:</strong></p><p>The EG4 6000XP is a cutting-edge 48V split-phase, off-grid inverter and charger, designed to revolutionize your energy needs. With an impressive 8kW of PV input capacity and an efficient 6kW continuous power output, it also serves as a battery 140A charger. What sets it apart is its scalability - you can parallel up to 16 units for an impressive 96kWs of output power while controlling multiple stations and units seamlessly using our advanced EG4 monitoring software.</p><p><strong>Performance Components</strong></p><ul><li><p>6000W rated output power</p></li><li><p>Parallel up to 16 units for 96kWs of output power</p></li><li><p>Built-in Switchgear for reduced installation costs and enhanced safety</p><ul><li><p>Save up to $300 with built-in breakers, disconnects and more!</p></li></ul></li><li><p>Transformer-Free Design</p></li><li><p>Dedicated Generator Connection</p></li><li><p>Inverter, AC Charger, and Solar Charge Controller</p></li></ul><p><strong>All-In-One</strong></p><ul><li><p>Everything needed to get started</p></li><li><p>Simple to install, easy to manage</p></li><li><p>Manages power from energy storage systems, and grid simultaneously</p></li><li><p>120/240V split phase</p></li></ul><p><strong>Efficiency</strong></p><ul><li><p>MPPT Efficiency 99%</p></li><li><p>Outperforms similar-sized competitors by an average of 7%</p></li><li><p>Battery Charging Efficiency 93%</p></li><li><p>Battery Discharging Efficiency 93%</p></li><li><p>50W Idle Consumption (with battery)</p></li></ul><p><strong>Monitoring</strong></p><ul><li><p>EG4 Monitoring App</p><ul><li><p><a target=\"_blank\" rel=\"noopener\" class=\"text-blue-600 underline\" href=\"https://play.google.com/store/apps/details?id=com.nfcx.eg4&amp;hl=en_US\">Google Play</a></p></li><li><p><a target=\"_blank\" rel=\"noopener noreferrer nofollow\" class=\"text-blue-600 underline\" href=\"https://apps.apple.com/us/app/eg4-monitor/id6448103545\">App Store</a></p></li></ul></li><li><p>Wi-Fi/4G/LAN</p></li><li><p>RS485</p></li></ul><p><strong>Comprehensive Certifications</strong></p><ul><li><p>UL 1741</p></li><li><p>Ingress Protection Rating: IP20</p></li></ul><ul><li><p>&nbsp;</p></li></ul>',1700.00,NULL,NULL,'b5ef143e-4e72-11f0-bbc5-06479488ad4b','EG4-6000XP',0.00,'[]',0,'calculated',0.00,'eg4-6000xp-off-grid-inverter-eg4-6000xp',1,'2025-06-19 02:13:49','2025-09-25 02:54:05'),('0fad8e12-4b1b-11f0-bbc5-06479488ad4b','Solarever 370 Watt Black Solar Panel','',75.00,NULL,NULL,'a0b3eb1a-4e72-11f0-bbc5-06479488ad4b','SE-166*83-370M-120N',0.00,'[]',0,'calculated',0.00,'solarever-370-watt-black-solar-panel-se-16683-370m-120n',0,'2025-06-17 01:33:24','2025-07-02 18:27:42'),('102bf11d-5210-11f0-bbc5-06479488ad4b','Growatt 11.4 kW Hybrid Inverter','<p>The Growatt 11.4kW grid-tie inverter MIN11400TL-XH-US offers exceptional performance for large-scale residential or commercial solar setups. Equipped with four MPP trackers, the Growatt grid tie inverter ensures maximum energy harvest from multi-array installations, even in shaded areas. Its durable NEMA4X-rated enclosure allows reliable operation in harsh outdoor environments.&nbsp;&nbsp;</p><p>Advanced IoT integration provides hassle-free monitoring and management through intuitive apps, helping users maintain optimal system performance. The Growatt 11.4kW grid-tie inverter MIN11400TL-XH-US is a top-tier solution for those seeking efficiency, safety, and scalability.&nbsp;</p><h3><strong>Features:</strong></h3><p><strong>Cutting-Edge Grid-Tie:</strong></p><ul><li><p>11400W Nominal Output</p></li><li><p>High 550 VDC Input (22800W Max PV!)</p></li><li><p>4 MPP Trackers, 2 Strings Per MPP Tracker</p></li><li><p>Up to 98.5% Efficiency</p></li></ul><p><strong>Quality Design:</strong></p><ul><li><p>–13°F to +140°F Operating Temperature</p></li><li><p>Natural Convection Cooling</p></li><li><p>NEMA4X (IP65) Rated</p></li><li><p>\'Aerospace grade\' Flame-retardant Lightweight Materials</p></li></ul><p><strong>Communication:</strong></p><ul><li><p>Built-in 4G/Wi-Fi Communication with APP, IoT integrated Cloud and monitoring</p></li><li><p>IOS, Android &amp; Windows Apps</p></li></ul><p><strong>Advanced Protection &amp; Safety:</strong></p><ul><li><p>UL Certified (1741)</p></li><li><p>Type III AC Surge Protection</p></li><li><p>AC Short Circuit Protection</p></li><li><p>Ground fault &amp; Grid Monitoring</p></li><li><p>AFCI Protection</p></li><li><p>Rapid Shutdown Capable, RFCI Protection</p></li><li><p>Anti-islanding Protection</p></li><li><p>Residual-Current Monitoring</p></li></ul><p>SKU: 1519073</p><p>Rated Output Power: 11400W</p><p>Max PV Input: 22,800W</p><p>Max MPPT Operating Voltage: 550V</p><p>Rated AC Output: 240V</p><p>Max Output Current: 48A</p><p>UL Certified: Yes</p>',700.00,NULL,'/uploads/datasheets/1750888965526-2if4jthst46.pdf',NULL,'MIN 11400TL-XH-US',0.00,'[]',0,'calculated',0.00,'growatt-114-kw-hybrid-inverter-min-11400tl-xh-us',1,'2025-06-25 22:02:19','2025-08-06 18:03:30'),('11eb2c90-b3e8-11f0-9ae1-0637a5b9918d','EG4 LL-S Lithium Battery | 48V 100AH | Server Rack Battery','<p><strong>EG4 LL-S Lithium Battery | 48V 100AH | Server Rack Battery</strong><br></p><p>The EG4 LL-S 48V 100Ah Server Rack Battery is a high-performance lithium iron phosphate (LiFePO₄) energy storage solution designed for demanding residential application. With a 5.12kWh capacity, and over 7,000 deep discharge cycles at 80% DoD, it offers long-lasting, reliable power. The integrated LCD touchscreen provides real-time battery insights, while advanced safety features like an Emergency Stop (RSD), dual fire arrestors, ensure peace of mind. Built for seamless integration, the LL-S supports closed-loop communication with leading inverter brands via RS-485 and CAN bus ports and allows parallel scalability of up to 64 batteries for large scale systems. UL 1973 and UL 9540 certifications further validate its safety and performance standards.</p><p><strong>Key Features</strong><br></p><ul><li><p>Built-In LCD Touchscreen – Allows real-time monitoring of battery status, voltage, cycles, and more for easy diagnostics and system management.</p></li><li><p>Advanced Communication – Equipped with RS-485 and CAN bus ports for seamless closed-loop integration with top inverter brands.</p></li><li><p>Parallel Capability – Supports up to 64 batteries in parallel, enabling scalable systems up to 327.7kWh.</p></li><li><p>Enhanced Safety Features – Includes an E-Stop (Rapid Shutdown), Dual Fire Arrestors, for added protection.</p></li><li><p>High-Capacity Performance – Delivers 5.12kWh of energy at 51.2V with 100Ah capacity and over 7,000 cycles at 80% DoD.</p></li><li><p>Certified Reliability – UL 1973 recognized, UL 9540A tested, and UL 9540 listed for trusted residential and commercial use.</p></li></ul>',1600.00,NULL,'/uploads/datasheets/1761646973554-lbfpev6ukk9.pdf','a98c7b21-4e72-11f0-bbc5-06479488ad4b','1511082',0.00,'[{\"type\":\"fixed\",\"name\":\"Standard Shipping\",\"description\":\"3-5 business days\",\"cost\":9.99},{\"type\":\"local_pickup\",\"name\":\"Local Pickup\",\"description\":\"Pick up from our location\",\"warehouse_ids\":[\"main-warehouse-id\"]}]',0,'calculated',0.00,'eg4-ll-s-lithium-battery-48v-100ah-server-rack-battery-1511082',1,'2025-10-28 10:22:56','2025-10-28 10:25:18'),('170ada74-bc35-11f0-9ad4-0637a5b9918d','Growatt Smart Electricity Meter Kit','<p>SM-US-200</p>',170.00,NULL,NULL,'b5ef143e-4e72-11f0-bbc5-06479488ad4b','SM-US-200',0.00,'[]',0,'calculated',0.00,'growatt-smart-electricity-meter-kit-sm-us-200',1,'2025-11-07 23:54:25','2025-11-07 23:54:25'),('1a6f6223-4abe-11f0-bbc5-06479488ad4b','Gstar 365 Watt Black Bifacial Solar Panel','<h3><strong>Gstar 365W Bifacial 120 Half-cut Mono Solar Panel&nbsp;</strong></h3><p>Bifacial Single Glass 9BB Half-cut Mono Perc</p><p><strong>KEY FEATURES</strong></p><p>10BB Half-cut Technology: New circuit design, lower internal current, lower Rs loss dopped wafer<br>Significantly Lower The Risk Of Hot Spot: Special circuit design with much lower hot spot temperature<br>Double Power Output: For higher power output, backside power output can be increases 5-25%&nbsp;<br>PID Resistance: Excellent Anti-PID performance guarantee via optimized<br>mass-production process and materials control</p><p><strong>Product Details</strong><br>Mfr. Part Number: GSP6G60M-365BT<br>Weight: 42.99 lb<br>Dimensions: 69.09 x 40.86 x 1.37 in<br>Manufacturer: Gstar</p>',85.00,NULL,NULL,'a0b3eb1a-4e72-11f0-bbc5-06479488ad4b','GSP6G60M-365BT',0.00,'[]',0,'calculated',0.00,'gstar-365-watt-black-bifacial-solar-panel-gsp6g60m-365bt',0,'2025-06-16 14:27:59','2025-07-02 18:30:28'),('1ae455f8-4abe-11f0-bbc5-06479488ad4b','Gstar 360 Watt Black Bifacial Solar Panel','<h2 style=\"text-align: left\"><strong>Gstar 360W Bifacial 120 Half-Cut Mono Solar Panel&nbsp;</strong></h2><p style=\"text-align: left\">Bifacial Single Glass 9BB Half-cut Mono Perc</p><p style=\"text-align: left\">&nbsp;</p><h3 style=\"text-align: left\"><strong>KEY FEATURES</strong></h3><ul><li><p><strong>&nbsp;10BB Half-cut Technology: </strong>New circuit design, lower internal current, lower Rs loss dopped wafer</p></li><li><p><strong>Significantly Lower The Risk Of Hot Spot:</strong> Special circuit design with much lower hot spot temperature</p></li><li><p><strong>Double Power Output:</strong> For higher power output, backside power output can be increases 5-25%&nbsp;</p></li><li><p><strong>PID Resistance:</strong> Excellent Anti-PID performance guarantee via optimized<br>mass-production process and materials control</p></li></ul><p style=\"text-align: left\">&nbsp;</p><h3 style=\"text-align: left\"><strong>Product Details</strong></h3><ul><li><p>Mfr. Part Number: GSP6G60M-360BT</p></li><li><p>Weight: 42.99 lb</p></li><li><p>Dimensions: 69.09 x 40.86 x 1.37 in</p></li><li><p>Manufacturer: Gstar</p></li></ul>',150.00,NULL,'/uploads/datasheets/1750862339562-4w6uzfhwwob.pdf','a0b3eb1a-4e72-11f0-bbc5-06479488ad4b','GSP6G60M-360BT',0.00,'[{\"type\":\"fixed\",\"name\":\"Standard Shipping\",\"description\":\"3-5 business days\",\"cost\":500},{\"type\":\"local_pickup\",\"name\":\"Local Pickup\",\"description\":\"Pick up from our location\",\"warehouse_ids\":[\"west-warehouse-id\"]}]',0,'calculated',0.00,'gstar-360-watt-black-bifacial-solar-panel-gsp6g60m-360bt',1,'2025-06-16 14:28:00','2025-10-24 03:14:04'),('1bd8150c-4abe-11f0-bbc5-06479488ad4b','Trina 250 Watt Black Solar Panel','<p><strong>The 250 watt TSM-250PA05 has a great price per watt!</strong></p><ul><li><p>15.3% max efficiency</p></li><li><p>250W max power output</p></li><li><p>10 Year product warranty</p></li><li><p>25 Year linear power warranty</p></li></ul>',50.00,NULL,NULL,'a0b3eb1a-4e72-11f0-bbc5-06479488ad4b','TSM-250PA05',0.00,'[]',0,'calculated',0.00,'trina-250-watt-black-solar-panel-tsm-250pa05',0,'2025-06-16 14:28:01','2025-08-03 03:48:36'),('1c21d00c-4abe-11f0-bbc5-06479488ad4b','Mixed 250-300 Watts Solar Panels','Auto-created product from order import',55.00,NULL,NULL,'a0b3eb1a-4e72-11f0-bbc5-06479488ad4b','mixed-250-300',0.00,'[{\"type\":\"fixed\",\"name\":\"Standard Shipping\",\"description\":\"3-5 business days\",\"cost\":9.99},{\"type\":\"local_pickup\",\"name\":\"Local Pickup\",\"description\":\"Pick up from our location\",\"warehouse_ids\":[\"main-warehouse-id\"]}]',0,'calculated',0.00,'mixed-250-300-watts-solar-panels-mixed-250-300',1,'2025-06-16 14:28:02','2025-10-25 01:34:08'),('1c3e237e-4abe-11f0-bbc5-06479488ad4b','Aptos 370 Watt Black Bifacial Solar Panel','Our DNA Series Impressively combines advanced technologies to maximize performance. Our patented Dual Nano Absorber (DNA) technology allows the panel to operate at high efficiencies in extreme temperature environments.\n\n\nFeature Bullets\n\nOptimized with patented Dual Nano Absorber (DNA) technology\nRobust product design is resilient in extreme weather. Up to 5400 Pa snow load and 6200 Pa wind load\nAll-black design for pristine aesthetics\nIndustry leading 30-year warranty\nAdvanced split cell technology with 9 ultra-thin busbars allows for less resistance and more photon capture\nAn ideal solution for applications affected by shading\nProduce up to 30% more energy with rear-side generation\nSpecifications:\n\n\nLength: 69.1 in\nWidth: 40.9 in\nHeight: 1.3 in\nCells Technology: Monocrystalline (Mono)\nMaximum Power (Pmax): 370 W STC\nMaximum Power Voltage (Vmp): 34.5 V STC\nMaximum Power Current (Imp): 10.72 A STC\nOpen-Circuit Voltage (VOC): 41.4 V STC\nShort-Circuit Current (Isc): 11.26 A STC\nMaximum System Voltage: 1500 VDC (UL & IEC)\nMaximum Series Fuse Rating: 20 A\nModule Efficiency: 20.28%\nFrame Material: Anodized Aluminum Alloy with 400 m Mounting Holes\nFront Glass: 3.2 mm, High Transmission, Anti-Reflection Coated, Low Iron, Tempered Glass\nFrame Color: Black\nBacksheet Color: Black\nIrradiance: 1000 W/m2 STC/800 W/m2 NOCT\nOutput Cables: 4 mm2 (EU)12AWG\nConnector Type: Staubli EVO2\nFire Type: Class C Type 1\nPressure Rating: 5400 Pa Snow, 6200 Pa Wind\nCell Temperature: 25 deg C STC\nAmbient Temperature: 20 deg C NOCT\nTemperature Coefficients of Pmax: -0.36%/deg C\nTemperature Coefficients of Open-Circuit Voltage (VOC): -0.28%/deg C\nTemperature Coefficients of Isc: 0.0449%/deg C\nNominal Operating Cell Temperature: 45 deg C\nAir Mass (AM): 1.5 STC/1.5 NOCT\nJunction Box: IP68 Rated, 3/8 Bypass Diodes\nEncapsulant: POE\nStandards: cULus, CE, CSAus, TUV, ETL, PV Cycle, MCS, IEC, UL\nWarranty: 30 Years Product, 30 Years Linear Performance\nWeight: 42.9 lb\nApplication: Residential, Commercial, Utility',85.00,NULL,'/uploads/datasheets/1755522440672-7ltcw93ag3g.pdf','a0b3eb1a-4e72-11f0-bbc5-06479488ad4b','DNA-120-BF26-370W',0.00,'[]',0,'calculated',0.00,'aptos-370-watt-black-bifacial-solar-panel-dna-120-bf26-370w',0,'2025-06-16 14:28:02','2025-11-27 14:01:34'),('1c42701b-4abe-11f0-bbc5-06479488ad4b','Sunmac 405 Watt Solar Panel','<p><strong>Sunmac Solar SM405-M754SH-BB 405Watt 108 1/2 Cells BoB Monocrystalline 30mm Black Frame Solar Panel</strong></p><p>Sunmac Solar provides high efficiency PERC PV modules at an extremely competitive price by working with our production partners in Asia with 2 GW of annual manufacturing capacity.</p><ul><li><p>Excellent Cell Efficiency - MBB technology reduces the distance between busbars and finger grid lines which increase power output</p></li><li><p>Improved Aesthetics - Compared to conventional modules, our full black modules have a more uniform appearance and superior aesthetics</p></li><li><p>Better Weak Illumination Response - More power output in weak light conditions, such as hazy or cloudy skies and early morning sunlight</p></li></ul><p><strong>Specifications:</strong></p><ul><li><p>Watt: 390</p></li><li><p>Length (in.): 67.87</p></li><li><p>Width (in.): 44.64</p></li><li><p>Height (in.): 1.18</p></li><li><p>Weight: 45.19 lbs</p></li></ul>',110.00,NULL,'/uploads/datasheets/1750597282742-tuea2vqfi2r.pdf','a0b3eb1a-4e72-11f0-bbc5-06479488ad4b','SM405-M754SH-BB',0.00,'[]',0,'calculated',0.00,'sunmac-405-watt-solar-panel-sm405-m754sh-bb',0,'2025-06-16 14:28:02','2025-11-11 20:02:03'),('1cb90b05-4abe-11f0-bbc5-06479488ad4b','Canadian Solar Silver 325 W Solar Panel','Auto-created product from order import',50.00,NULL,NULL,NULL,'AUTO-1750084083461-X6JYS',0.00,'[]',0,'calculated',0.00,'canadian-solar-silver-325-w-solar-panel-auto-1750084083461-x6jys',0,'2025-06-16 14:28:03','2025-07-02 18:29:32'),('1cbfb4ac-4abe-11f0-bbc5-06479488ad4b','Mixed Black 300','Auto-created product from order import',46.67,NULL,NULL,'a0b3eb1a-4e72-11f0-bbc5-06479488ad4b','AUTO-1750084083504-1SVAF',0.00,'[]',0,'calculated',0.00,'mixed-black-300-auto-1750084083504-1svaf',0,'2025-06-16 14:28:03','2025-08-11 17:26:52'),('1cc533b7-4abe-11f0-bbc5-06479488ad4b','Mixed San Tan Black 320','Auto-created product from order import',50.00,NULL,NULL,NULL,'AUTO-1750084083540-KLHXR',0.00,'[]',0,'calculated',0.00,'mixed-san-tan-black-320-auto-1750084083540-klhxr',0,'2025-06-16 14:28:03','2025-10-28 15:49:55'),('1cd115be-4abe-11f0-bbc5-06479488ad4b','Aionrise 360 Watt Black Solar Panel','Auto-created product from order import',105.00,NULL,'/uploads/datasheets/1750658962740-offlyy3zza.pdf','a0b3eb1a-4e72-11f0-bbc5-06479488ad4b','AION66G1-360',0.00,'[]',0,'calculated',0.00,'aionrise-360-watt-black-solar-panel-aion66g1-360',0,'2025-06-16 14:28:03','2025-07-02 18:34:15'),('1daebfe0-4abe-11f0-bbc5-06479488ad4b','Sunpreme Silver 400 Watt Solar Panel','Auto-created product from order import',80.00,NULL,NULL,'a0b3eb1a-4e72-11f0-bbc5-06479488ad4b','AUTO-1750084085071-NJXXD',0.00,'[]',0,'calculated',0.00,'sunpreme-silver-400-watt-solar-panel-auto-1750084085071-njxxd',0,'2025-06-16 14:28:05','2025-09-09 19:19:47'),('1dc7dbd6-4abe-11f0-bbc5-06479488ad4b','DMEGC 450 Watt Bifacial Solar Panels','<p>If you need delivery, and you are not in Utah, the minimum order quantity is 15 panels.</p><p>The DM450M10RT-B54HBT-L is an advanced N-type bifacial solar module with double glass construction, offering high efficiency and reliability. ​ It is designed with DMEGC Advanced Black Technology for outstanding aesthetics and is suitable for harsh environmental conditions such as salt, ammonia, sand, and hail. ​ The module is environmentally friendly, featuring a low carbon footprint, PFAS-free materials, and recyclable components. ​</p><p><strong>Key Features:</strong></p><ul><li><p><strong>Power Output:</strong> Available in 450W models with a maximum efficiency of 23.0%. ​</p></li><li><p><strong>Durability:</strong> 30-year linear power warranty with ≤1% first-year degradation and ≤0.4% annual degradation over 30 years. ​</p></li><li><p><strong>Certifications:</strong> IEC 61215, IEC 61730, IEC 62716 (Ammonia Corrosion), IEC 61701 (Salt Mist Corrosion), IEC TS 63342 (LeTID), IEC 60068 (Dust &amp; Sand). ​</p></li><li><p><strong>Reliability:</strong> Resistant to extreme environmental conditions and designed for long-term performance. ​</p></li><li><p><strong>Operating Conditions:</strong> Operates in temperatures ranging from -40°C to +85°C, with a maximum system voltage of 1000/1500V DC. ​</p></li><li><p><strong>Temperature Characteristics:</strong> Nominal Module Operating Temperature (NMOT) of 42±2°C, with a temperature coefficient of Pmax at -0.29%/°C. ​</p></li></ul><p><strong>Specifications:</strong></p><ul><li><p><strong>Cell Type:</strong> N-type Mono-crystalline (108 cells, 6×18 layout). ​</p></li><li><p><strong>Dimensions:</strong> 1762 × 1134 × 30 mm - 69.37\" x 44.6\" x 1.18\" inches</p></li><li><p><strong>Weight:</strong> 20.4 kg. ​</p></li><li><p><strong>Front and Rear Cover:</strong> 1.6 mm heat-strengthened glass. ​</p></li><li><p><strong>Electrical Performance:</strong> Maximum power ranges from 440W to 460W under STC conditions, with module efficiency up to 23.0%. ​</p></li><li><p><strong>Packaging:</strong> 36 pieces per pallet, 936 pieces per 40HQ container. ​</p></li></ul><p><strong>Certifications and Management Systems:</strong> ​</p><ul><li><p>ISO 9001, ISO 14001, ISO 45001, ISO 50001, ISO 27001, and SA 8000 standards ensure quality, environmental responsibility, energy efficiency, and social responsibility.</p></li></ul><p>This module is ideal for applications requiring high performance, durability, and sustainability, making it a reliable choice for residential, commercial, and industrial solar installations.</p>',105.00,NULL,'/uploads/datasheets/1761926427859-4j0cinshjh5.pdf','a0b3eb1a-4e72-11f0-bbc5-06479488ad4b','DM450M10RT-B54HBT-L',0.00,'[{\"type\":\"fixed\",\"name\":\"Standard Shipping\",\"description\":\"3-5 business days\",\"cost\":50},{\"type\":\"local_pickup\",\"name\":\"Local Pickup\",\"description\":\"Pick up from our location\",\"warehouse_ids\":[\"main-warehouse-id\"]}]',0,'calculated',0.00,'dmegc-450-watt-bifacial-solar-panels-dm450m10rt-b54hbt-l',1,'2025-06-16 14:28:05','2025-12-04 17:44:05'),('1e40a249-4abe-11f0-bbc5-06479488ad4b','Jinko 320 Watt Solar Panel','Auto-created product from order import',75.00,NULL,NULL,NULL,'AUTO-1750084086027-6P78B',0.00,'[]',0,'calculated',0.00,'jinko-320-watt-solar-panel-auto-1750084086027-6p78b',0,'2025-06-16 14:28:06','2025-08-08 19:43:41'),('1e59fc28-4abe-11f0-bbc5-06479488ad4b','Axitec 330 Watt Solar Panel','Auto-created product from order import',80.00,NULL,NULL,'a0b3eb1a-4e72-11f0-bbc5-06479488ad4b','AC-330P/72S',0.00,'[]',0,'calculated',0.00,'axitec-330-watt-solar-panel-ac-330p72s',0,'2025-06-16 14:28:06','2025-07-02 18:28:19'),('1e5d2613-4abe-11f0-bbc5-06479488ad4b','Trina Black 240 Watt Solar Panel','Auto-created product from order import',50.00,NULL,NULL,'a0b3eb1a-4e72-11f0-bbc5-06479488ad4b','AUTO-1750084086214-70LAJ',0.00,'[]',0,'calculated',0.00,'trina-black-240-watt-solar-panel-auto-1750084086214-70laj',0,'2025-06-16 14:28:06','2025-09-08 19:09:42'),('1e77eb8b-4abe-11f0-bbc5-06479488ad4b','Shallow Unistrut 10 Foot','Unistrut 10 Foot Silver Half Slotted Electro-Galvanized Strut Channel',30.00,NULL,NULL,'be84ed54-4e72-11f0-bbc5-06479488ad4b','ZB14HS10EG',0.00,'[]',0,'calculated',0.00,'shallow-unistrut-10-foot-zb14hs10eg',1,'2025-06-16 14:28:06','2025-12-11 03:21:55'),('1e904f54-4abe-11f0-bbc5-06479488ad4b','Solar Panel Mid Clamp For Standard Unistrut','Mid clamps',3.00,NULL,NULL,'be84ed54-4e72-11f0-bbc5-06479488ad4b','ABTGR2861',0.00,NULL,0,'calculated',0.00,'solar-panel-mid-clamp-for-standard-unistrut-abtgr2861',1,'2025-06-16 14:28:06','2025-06-27 13:27:59'),('1f63c704-ab6f-11f0-8e1b-0637a5b9918d','Tigo Access Point (TAP): Zigbee and BLE','',40.00,NULL,NULL,'b5ef143e-4e72-11f0-bbc5-06479488ad4b','1594008',0.00,'[]',0,'calculated',0.00,'tigo-access-point-tap-zigbee-and-ble-1594008',1,'2025-10-17 15:37:00','2025-10-17 15:37:00'),('21a0344a-943a-11f0-95d2-0637a5b9918d','EG4 280Ah WallMount Battery Paralleling Cable Kit','<p>The EG4 All Weather Battery Paralleling Cables&nbsp;are designed to facilitate secure and efficient parallel connections between batteries in your solar system. This set includes high-quality cables to ensure reliable performance and easy installation.</p><h4><strong>Includes:</strong></h4><ul><li><p><strong>Red Positive Battery Parallel Cable (53.1 in.)</strong>: Qty 1</p></li><li><p><strong>Black Negative Battery Parallel Cable (53.1 in.)</strong>: Qty 1</p></li><li><p><strong>Parallel Communication Cable (59.1 in.)</strong>: Qty 1</p></li></ul><p><em>&nbsp;From purchase to installation and beyond, our USA-based team offers lifetime support—contact us with any questions.</em></p>',170.00,NULL,NULL,'b5ef143e-4e72-11f0-bbc5-06479488ad4b','paralleling-cable-kit',0.00,'[{\"type\":\"free\",\"name\":\"Free Shipping\",\"description\":\"3-5 business days\"}]',0,'calculated',0.00,'eg4-280ah-wallmount-battery-paralleling-cable-kit-paralleling-cable-kit',1,'2025-09-18 02:49:44','2025-10-13 16:40:17'),('252606da-bd93-11f0-9ad4-0637a5b9918d','SnapNrack | TopSpeed™ | Solar Panel Roof Mount Kit','<p>Introducing the SnapNrack TopSpeed™ Roof Mount System – your solution for efficient and stylish solar installation. With rapid installation, durable design, and a sleek aesthetic, TopSpeed is the future of solar mounting.</p><p><strong>Key Features:</strong></p><ul><li><p><strong>Effortless Efficiency:</strong> Innovative design for fast, high-quality installation.</p></li><li><p><strong>Built to Last:</strong> Durable materials ensure long-term solar performance.</p></li><li><p><strong>Aesthetically Sleek:</strong> Seamlessly integrates with various roofs for a polished look.</p></li></ul><p>Elevate your solar projects with the SnapNrack TopSpeed Roof Mount System – where form meets function flawlessly.</p><p>Need help designing your SnapNrack rooftop mount system? Check out their design tool user guide <a target=\"_blank\" rel=\"noopener noreferrer nofollow\" class=\"text-blue-600 underline\" href=\"https://www.youtube.com/watch?v=aspDgsxo_LU\">here</a>.</p>',15.00,NULL,'/uploads/datasheets/1762710010680-ygcxuazld6.pdf','be84ed54-4e72-11f0-bbc5-06479488ad4b','16180027-K',0.00,'[]',0,'calculated',0.00,'snapnrack-topspeed-solar-panel-roof-mount-kit-16180027-k',1,'2025-11-09 17:40:12','2025-11-09 17:40:12'),('25c67a2e-52ca-11f0-bbc5-06479488ad4b','APsystems DS3-L Dual Microinverter','<p><strong>Dual-module // Single phase // 3rd generation</strong><br><br>APsystems\' 3rd generation of dual-module, single-phase microinverters, the DS3 product family represents the culmination of years of power conversion expertise and innovation in high-efficiency, high-density power conversion to maximize the peak performance of today\'s high-capacity PV modules.<br><br>The DS3 series reaches unprecedented levels of power output and is fully backwards compatible with QS1 and YC600 microinverters and accessories. It features 2 input channels, each with independent MPPT, and encrypted wireless Zigbee communication. An innovative and compact design makes the product lighter while maximizing power production, and silicone-encapsulated components reduce stress on electronics, facilitate thermal dissipation, and enhance weatherproofing. Reliability is significantly increased thanks to 20% fewer components than previous generations.<br><br>The DS3 series is grid-interactive and fully compliant with CA Rule 21 requirements. With its unparalleled performance, efficiency of 97%, and increased reliability, the APsystems DS3 series is a gamechanger for residential and commercial solar.<br><br><strong>Product Models</strong></p><ul><li><p>DS3-S - 640VA output, ideal for PV modules up to 400W+</p></li><li><p>DS3-L - 748VA output, ideal for PV modules up to 480W+</p></li><li><p>DS3 - 880VA output, ideal for PV modules up to 550W+</p></li><li><p>(+ means higher wattage PV modules will not negatively impact the inverter)</p></li></ul><p><strong>A Class Apart</strong><br>What is so unique about these new microinverters? The DS3 series utilizes a new architecture that can manage far higher capacities of PV modules than conventional 1:1 microinverters.<br><br>The DS3-S and DS3-L have also been specifically designed to maximize the output on each residential circuit. Compared with competing devices, the DS3-S has up to 37% more AC output and the DS3-L up to 60% more output power per channel than conventional microinverters. For many installers around the world, the new DS3 series has become a strong competitive advantage helping them save money while winning more business.<br><br><strong>Key Features</strong></p><ul><li><p>Single-Phase, Dual-Module Microinverter</p></li><li><p>640W, 768W, And 880W Models</p></li><li><p>Dual, Independent Mppt</p></li><li><p>Encrypted Zigbee Wireless</p></li><li><p>Accommodates 2 Pv Modules Up To 550Wp (Ds3 Model)</p></li><li><p>Certified To Ul1741 Sa (Ca Rule 21) Standard</p></li><li><p>Compatible With Qs1 &amp; Yc600 Products &amp; Accessories</p></li></ul>',180.00,NULL,'/uploads/datasheets/1750968859753-90tb234aomt.pdf','b5ef143e-4e72-11f0-bbc5-06479488ad4b','DS3-L-NA-768VA',0.00,'[{\"type\":\"local_pickup\",\"name\":\"Local Pickup\",\"description\":\"Pick up from our location\",\"warehouse_ids\":[\"main-warehouse-id\"]},{\"type\":\"free\",\"name\":\"Standard Shipping\",\"description\":\"3-5 business days\"}]',0,'calculated',0.00,'apsystems-ds3-l-dual-microinverter-ds3-l-na-768va',1,'2025-06-26 20:14:21','2025-10-07 04:03:43'),('27bff221-719f-11f0-9a85-0637a5b9918d','Tigo Cloud Connect Advanced Outdoor Enclosure Kit','',250.00,NULL,NULL,'b5ef143e-4e72-11f0-bbc5-06479488ad4b','348-00000-52',0.00,'[{\"type\":\"local_pickup\",\"name\":\"Local Pickup\",\"description\":\"Pick up from our location\",\"warehouse_ids\":[\"main-warehouse-id\"]},{\"type\":\"free\",\"name\":\"Standard Shipping\",\"description\":\"3-5 business days\"}]',0,'calculated',0.00,'tigo-cloud-connect-advanced-outdoor-enclosure-kit-348-00000-52',1,'2025-08-05 01:54:42','2025-10-23 12:10:59'),('2afd6dcf-8e79-11f0-95d2-0637a5b9918d','EG4 Indoor Buildable Conduit Box | Designed for EG4-WallMount Indoor Battery','<p><strong>EG4 INDOOR BUILDABLE CONDUIT BOX | ESS67-PP-280A3</strong></p><p>The EG4 Indoor Buildable Conduit Box allows users a simple and effective way to protect cables and connections between battery and inverter. The conduit box is designed to pair the<a target=\"_blank\" rel=\"noopener\" class=\"text-blue-600 underline\" href=\"https://signaturesolar.com/eg4-wallmount-indoor-battery-48v-280ah-14-3kwh-indoor-heated-ul1973-ul9540a-10-year-warranty?searchid=1517166&amp;search_query=indoor\"> EG4 WallMount Indoor 280Ah Lithium Battery</a> with either the EG4 FlexBOSS18, FlexBOSS21, 18kPV, 12kPV, 6000XP, or the<br>12000XP inverters.</p><p><strong>Key Features:</strong></p><ul><li><p>Direct fit combination of EG4 FlexBOSS18, FlexBOSS21, 18kPV, 12kPV, 6000XP, or the 12000XP inverters with <a target=\"_blank\" rel=\"noopener\" class=\"text-blue-600 underline\" href=\"https://signaturesolar.com/eg4-wallmount-indoor-battery-48v-280ah-14-3kwh-indoor-heated-ul1973-ul9540a-10-year-warranty?searchid=1517046&amp;search_query=indoor\"><strong>EG4 WallMount Indoor 280Ah Lithium Batteries</strong></a></p></li><li><p>Protects cables and connections between EG4 inverters and batteries</p></li><li><p>Protects cables and connections on paralleled batteries, with side knockouts for battery to battery cable runs</p></li><li><p>Multiple side and top knockouts for custom use with non-EG4 inverters</p></li><li><p>Box size allows for proper wire spacing per NEC code</p></li><li><p>Easy and rapid assembly with included hardware</p></li><li><p>&nbsp;Compact flatpack for easy shipping</p></li></ul>',130.00,NULL,'/uploads/datasheets/1757531305006-5dev7lbihnc.pdf','b5ef143e-4e72-11f0-bbc5-06479488ad4b','EG4SPIDWMBCNDTSHRD',0.00,'[{\"type\":\"free\",\"name\":\"Standard Shipping\",\"description\":\"3-5 business days\"}]',0,'calculated',0.00,'eg4-indoor-buildable-conduit-box-designed-for-eg4-wallmount-indoor-battery-eg4spidwmbcndtshrd',1,'2025-09-10 19:05:51','2025-10-13 16:46:46'),('2b6d0117-80f7-11f0-8e5b-0637a5b9918d','EG4 FlexBOSS18 13kW Hybrid Inverter','<p><strong>EG4 FlexBOSS18 Hybrid Inverter | 48V Split Phase | 18kW PV Input</strong></p><p>The EG4 FlexBOSS18 Hybrid Inverter delivers professional-grade performance at an accessible price point, making it the ideal choice for both installers and DIY enthusiasts looking for a cost-effective hybrid solar solution. Designed to maximize efficiency and savings, this inverter offers 13kW continuous output (with PV), 18kW maximum solar input, and 10kW battery-only output capability. Whether you\'re aiming to reduce reliance on the grid or build a powerful off-grid system, the FlexBOSS18 provides the perfect balance of affordability, performance, and versatility.</p><h3><strong>Key Features:</strong></h3><ul><li><p><strong>High Power Output:</strong> 13kW continuous output with PV, 18kW solar input, and 10kW battery-only output.</p></li><li><p><strong>Versatile Compatibility:</strong> Works flawlessly with EG4 batteries and pairs seamlessly with the EG4 GridBOSS MID for enhanced functionality.</p></li><li><p><strong>Certified &amp; Compliant:</strong> UL1741 certification for safety and reliability.</p></li><li><p><strong>Cost-Effective Hybrid Solution:</strong> Affordable entry into hybrid solar with professional-grade capabilities.</p></li><li><p><strong>Flexible Installation:</strong> Designed for easy integration into both residential and commercial setups.</p></li></ul><h2><strong>Seamless Integration with </strong><a target=\"_blank\" rel=\"noopener\" class=\"text-blue-600 underline\" href=\"https://signaturesolar.com/eg4-gridboss-vs-mid-200a-service-entrance/\"><strong>EG4 GridBOSS MID</strong></a></h2><p>The FlexBOSS18 pairs perfectly with the EG4 GridBOSS MID, optimizing energy management and grid interaction. This integration reduces installation costs, simplifies the setup, and eliminates the need for additional breakers, transfer switches, and more, all within one compact solution. It also enables time-of-use optimization, load shifting, and backup power prioritization, giving you enhanced control over your energy use. By combining the FlexBOSS18 with the <a target=\"_blank\" rel=\"noopener\" class=\"text-blue-600 underline\" href=\"https://signaturesolar.com/eg4-gridboss-vs-mid-200a-service-entrance/\">EG4 GridBOSS MID</a>, users can maximize energy efficiency, reduce dependency on the grid, and take full control of their solar energy system.</p><h2><strong>Why Choose the EG4 FlexBOSS18?</strong></h2><p>The FlexBOSS18 offers higher power output, increased PV capacity, and enhanced hybrid capabilities at an accessible price point. Its UL1741 certifications ensure compliance with strict industry regulations, making it a reliable and future-proof investment for both grid-tied and off-grid applications.</p><h3><strong>Elevate Your Energy System</strong></h3><p>Discover the power, flexibility, and affordability of the EG4 FlexBOSS18 Hybrid Inverter. Whether you’re upgrading an existing system or starting from scratch, the FlexBOSS18 delivers the performance and reliability needed to take control of your energy future.</p><p><a target=\"_blank\" rel=\"noopener\" class=\"text-blue-600 underline\" href=\"https://signaturesolar.com/eg4/\"><strong>Explore more EG4 products and find the perfect solution for your energy needs.</strong></a></p>',3380.00,NULL,'/uploads/datasheets/1756046030507-xrndw0j3kl.pdf','b5ef143e-4e72-11f0-bbc5-06479488ad4b','EG4INVFLXBOSS18V1',0.00,'[{\"type\":\"free\",\"name\":\"Free Shipping\",\"description\":\"3-5 business days\"},{\"type\":\"local_pickup\",\"name\":\"Local Pickup\",\"description\":\"Pick up from our location\",\"warehouse_ids\":[\"east-warehouse-id\"]}]',0,'calculated',0.00,'eg4-flexboss18-13kw-hybrid-inverter-eg4invflxboss18v1',1,'2025-08-24 14:32:32','2025-11-28 15:51:28'),('328f5187-4d17-11f0-bbc5-06479488ad4b','Growatt 3.3KWH Solar Lithium Battery','Poweramp Growatt 3.3KWH Solar Battery ML33RTA 51.2V IP20 UN3480 4G/Y40/S/21',475.00,NULL,NULL,'a98c7b21-4e72-11f0-bbc5-06479488ad4b','ML33RTA',0.00,'[{\"type\":\"free\",\"name\":\"Standard Shipping\",\"description\":\"3-5 business days\"},{\"type\":\"local_pickup\",\"name\":\"Local Pickup\",\"description\":\"Pick up from our location\",\"warehouse_ids\":[\"main-warehouse-id\"]}]',0,'calculated',0.00,'growatt-33kwh-solar-lithium-battery-ml33rta',1,'2025-06-19 14:10:47','2025-09-17 20:54:38'),('335f887f-befe-11f0-9ad4-0637a5b9918d','EG4 280Ah WallMount All Weather Conduit Box','<p><a target=\"_blank\" rel=\"noopener noreferrer nofollow\" class=\"text-blue-600 underline\" href=\"https://signaturesolar.com/eg4-wallmount-all-weather-lithium-battery-48v-280ah-14-3kwh-lifepo4-all-weather-energy-storage-ul1973-ul9540a-10-year-warranty/\">The EG4 280Ah WallMount</a> All Weather Conduit Box safeguards cables and connections between your battery and inverter, providing protection against weather exposure and accidental damage. Designed to seamlessly pair <a target=\"_blank\" rel=\"noopener noreferrer nofollow\" class=\"text-blue-600 underline\" href=\"https://signaturesolar.com/eg4-wallmount-all-weather-lithium-battery-48v-280ah-14-3kwh-lifepo4-all-weather-energy-storage-ul1973-ul9540a-10-year-warranty/\">The EG4 280Ah WallMount</a> All Weather Battery with EG4 FlexBOSS21, 18kPV, and 12kPV inverters, it ensures a clean, durable, and secure installation for your energy storage system.</p><p><strong>Key Benefits:</strong><br>• <strong>Seamless Compatibility:</strong> Built to perfectly match the EG4 WallMount All Weather Lithium Battery and integrate smoothly with FlexBOSS21, 18kPV, and 12kPV inverters.<br>• <strong>Enhanced Protection:</strong> Shields cables and electrical connections from harsh weather, debris, and accidental impact for improved safety and long-term reliability.<br>• <strong>Streamlined Installation:</strong> Features pre-configured side knockouts and a straightforward design for quick, efficient mounting and cable management.<br><strong>• Durable Construction:</strong> Engineered with robust materials that stand up to demanding environments, maintaining performance in all weather conditions.<br>• <strong>Clean, Professional Finish:</strong> Provides a tidy look to your battery-inverter setup, minimizing clutter and improving accessibility during service or maintenance.</p><p><br><strong>Tech Specs:</strong></p><ul><li><p><strong>Exterior Dimensions:</strong> 24.13\" L × 10.57\" W × 9.06\" H</p></li><li><p><strong>Product Weight:</strong> 16.85 lbs</p></li><li><p><strong>Mounting Method:</strong> Direct top-mount to battery; can be secured to inverters using threaded inserts</p></li><li><p><strong>Not Compatible With:</strong> EG4 280Ah WallMount Indoor battery</p></li></ul><p></p><p><em>Whether it’s your first project or your fifth, our USA-based team is here for you. Lifetime support means you’re never on your own.</em></p>',170.00,NULL,'/uploads/datasheets/1762866025446-qyrxwvnbbra.pdf','b5ef143e-4e72-11f0-bbc5-06479488ad4b','1511071',0.00,'[{\"type\":\"free\",\"name\":\"Standard Shipping\",\"description\":\"3-5 business days\"}]',0,'calculated',0.00,'eg4-280ah-wallmount-all-weather-conduit-box-1511071',1,'2025-11-11 12:59:04','2025-11-11 13:01:59'),('3364d48f-5124-11f0-bbc5-06479488ad4b','EG4 WallMount Indoor Battery 14.3kWh','<h1><strong>EG4-WallMount Indoor Battery | 48V 280Ah | 14.3kWh | Indoor | Heated UL1973, UL9540A | 10-Year Warranty</strong></h1><p>The WallMount Indoor 14.3kWh batteries are ideal for low-voltage residential indoor energy storage applications. The batteries use lithium iron phosphate cells with the highest safety performance and an intelligent Battery Management System (BMS) that can monitor and record the voltage of each cell along with the current, voltage, and temperature of the module in real-time. The BMS also contains a passive balance function and an advanced battery control method, both of which improve the performance of the battery pack.</p><p><strong>Key Features:</strong></p><p><strong>ON-BOARD LCD TOUCH SCREEN</strong><br>Easy to see BMS monitoring, and selectable closed-loop communications with EG4, Schneider, Sol-Ark, Victron, Growatt, Megarevo, Luxpower, and Deye inverters.</p><p><strong>DUAL ON-BOARD FIRE ARRESTORS</strong><br>Offer fail-safe protection against thermal runaway.</p><p><strong>INTEGRATED SELF-HEATING FEATURE</strong><br>Internal heating keeps cells operating during cold temperatures.</p><p><strong>INTEGRATED BUSBARS</strong><br>The battery design comes manufactured with 600A internal busbars with multiple terminals (4 positive &amp; 4 negative) eliminating the need for external busbars when paralleling batteries and/or multiple inverters.</p><p><strong>INNOVATIVE EMERGENCY STOP FUNCTION</strong><br>The optional ESS disconnect can shut down all batteries and inverters (if equipped with rapid shut down capability) with the press of a button.</p><p><strong>THE PERFECT PARTNER TO EG4 INVERTERS</strong><br>The optional conduit box mates up directly to the connection ports of EG4 inverters allowing a sleek and efficient installation. For other inverters or stand-alone battery installation, the conduit box plugs should be installed.</p><p><strong>Module Operating Parameters</strong></p><ul><li><p><strong>Voltage:</strong> 51.2V</p></li><li><p><strong>Total Energy Capacity: </strong>14.3kWh</p></li><li><p><strong>Capacity:</strong> 280Ah</p></li><li><p><strong>Charging Voltage (Bulk/Absorb):</strong> 56.0V (+/-0.8V) to 56.2V (+/-0.2V)</p></li><li><p><strong>Float Voltage:</strong> 54V (+/-0.2V)</p></li><li><p><strong>Low DC Cutoff:</strong> 44.8V (adjustable start from 47V to 45.6V)</p></li><li><p><strong>Charging Current:</strong> Up to 200A (continuous), recommended range: 60A - 160A</p></li><li><p><strong>Discharging Current:</strong> Up to 200A (continuous), recommended: 160A</p></li></ul><p><strong>Environmental Parameters</strong></p><ul><li><p><strong>Charging Range:</strong> 32°F to ≈113°F (0°C to ≈45°C)</p></li><li><p><strong>Discharging Range:</strong> -4°F to ≈122°F (-20°C to ≈50°C)</p></li><li><p><strong>Storage Range:</strong> -4°F to ≈122°F (-20°C to ≈50°C)</p></li><li><p><strong>Ingress Protection:</strong> IP20</p></li></ul><p><strong>Charging/Discharging Protection</strong></p><ul><li><p><strong>Overcharging Protection:</strong> &gt;205A (10 sec), &gt;225A (3 sec)</p></li><li><p><strong>Temperature Protection:</strong> &lt;23°F or &gt;158°F (1 sec), &lt;-5°C or &gt;70°C (1 sec)</p></li></ul><p><strong>General Specifications</strong></p><ul><li><p><strong>Communication Ports: </strong>RS485/CAN Can be customized</p></li><li><p><strong>Cycle Life:</strong> &gt;8000 Cycles, 80% Depth of Discharge (DOD)</p></li><li><p><strong>Design Life:</strong> Over 15 Years</p></li><li><p><strong>Weight:</strong> 282.2 lbs. (128 kg)</p></li><li><p><strong>Safety Certifications:</strong> UL1973, UL 9540A (Testing)</p></li></ul>',3400.00,NULL,NULL,'a98c7b21-4e72-11f0-bbc5-06479488ad4b','WM-48-280-1-IN-LL-00',0.00,'[]',0,'calculated',0.00,'eg4-wallmount-indoor-battery-143kwh-wm-48-280-1-in-ll-00',1,'2025-06-24 17:53:57','2025-09-27 04:11:18'),('37dcb95c-5e83-11f0-8e5b-0637a5b9918d','Phono Solar 310 Watt Solar Panel','<ul><li><p><strong>Polycrystalline solar cell technology for a more affordable installation</strong></p></li><li><p><strong>Produces 14.8W per square feet to optimize larger roof spaces</strong></p></li><li><p><strong>Independently generates renewable energy for electric bill savings</strong></p></li></ul>',60.00,NULL,'/uploads/datasheets/1752258010458-5gzph2xnau.pdf','a0b3eb1a-4e72-11f0-bbc5-06479488ad4b','PS310P-24/T',0.00,'[{\"type\":\"fixed\",\"name\":\"Standard Shipping\",\"description\":\"3-5 business days\",\"cost\":500},{\"type\":\"local_pickup\",\"name\":\"Local Pickup\",\"description\":\"Pick up from our location\",\"warehouse_ids\":[\"main-warehouse-id\"]}]',0,'calculated',0.00,'phono-solar-310-watt-solar-panel-ps310p-24t',0,'2025-07-11 18:16:51','2025-09-14 20:04:38'),('3c401e22-b52c-11f0-9ae1-0637a5b9918d','MC4 Female End Box Of 100','',150.00,NULL,NULL,'b5ef143e-4e72-11f0-bbc5-06479488ad4b','MC4-female-end-100',0.00,'[]',0,'calculated',0.00,'mc4-female-end-box-of-100-mc4-female-end-100',1,'2025-10-30 01:03:24','2025-10-30 15:21:36'),('3d1d7ab9-4d14-11f0-bbc5-06479488ad4b','Longi 360 Watt Solar Panel','',70.00,NULL,NULL,'a0b3eb1a-4e72-11f0-bbc5-06479488ad4b','LR4-60HPH-360M',0.00,'[]',0,'calculated',0.00,'longi-360-watt-solar-panel-lr4-60hph-360m',0,'2025-06-19 13:49:36','2025-07-02 18:28:42'),('3e199864-c055-11f0-9ad4-0637a5b9918d','Growatt 3kW Stackable Off-Grid Inverter','<p>Multifunctional off grid solar inverter, integrated with a MPPT solar charge controller, a high frequency pure sine wave inverter and a UPS function module all in one machine. Perfect for off grid backup power and self-consumption applications. Transformerless design provides reliable power conversion in a compact size. Purchase two for 120/240V TRUE Split Capacity.</p><p>Growatt USB Wifi Monitoring device sold separately.</p><p><strong>Key Features:</strong></p><ul><li><p>24V battery system</p></li><li><p>PV Input 30-115VDC</p></li><li><p>Pure sine wave output 3KW</p></li><li><p>Inbuilt MPPT 80A High frequency inverter with small lightweight size</p></li><li><p>Overload, short circuit and deep discharge protection</p></li><li><p>Compatible to mains voltage or generator power</p></li><li><p>Parallel operation up to 6 unit</p></li><li><p>With CAN/RS485 for BMS communication</p></li><li><p>WIFI/ GPRS remote monitoring (optional)</p></li></ul>',800.00,NULL,'/uploads/datasheets/1763013276176-kywije9vlap.pdf','b5ef143e-4e72-11f0-bbc5-06479488ad4b','SPF 3000TL LVM-48P',0.00,'[]',0,'calculated',0.00,'growatt-3kw-stackable-off-grid-inverter-spf-3000tl-lvm-48p',1,'2025-11-13 05:54:39','2025-11-13 05:54:39'),('4599f1bb-7288-11f0-9985-0637a5b9918d','Tricky 1600 Watt Kit w/ Monitoring','<p>This kit will get you started with 1600 watts for your house. It outputs 240 volts, so you can hook it into an electrical panel, your air conditioning unit, a dryer outlet, etc. It also includes the ECU-R unit, so you can monitor how much power you are producing from each microinverter.</p><p>This is a great kit if you are not in Utah because we can ship it all to you free, and then you can pick up some solar panels locally (since solar panels cost so much to ship).</p>',790.00,NULL,NULL,'f1311ab6-6aa8-11f0-8da0-0637a5b9918d','trick-bundle-1600-monitoring',0.00,'[{\"type\":\"free\",\"name\":\"Standard Shipping\",\"description\":\"3-5 business days\"},{\"type\":\"local_pickup\",\"name\":\"Local Pickup\",\"description\":\"Pick up from our location\",\"warehouse_ids\":[\"main-warehouse-id\"]}]',1,'fixed',0.00,'tricky-1600-watt-kit-w-monitoring-trick-bundle-1600-monitoring',1,'2025-08-06 05:43:25','2025-08-06 05:47:05'),('47a0a491-4d16-11f0-bbc5-06479488ad4b','Tigo 7.6 kW Inverter','Tigo TSI-7.6kW-US “Hybrid” EI Inverter\nThe Tigo EI Inverter is the centerpiece of the Tigo Energy Intelligence (EI) solution. It orchestrates energy production and consumption (when coupled with the Tigo EI Battery). In addition, it enables module-level monitoring, optimization, and rapid shutdown when paired with Tigo TS4 MLPE (Module Level Power Electronics) through the EI platform.\n\nFeatures and– benefits\nAvailable in 3.8, 7.6 kW, and 11.4 kW models\nStorage-ready ‘hybrid’ inverter\nUp to 200% DC oversizing (2:1 DC/AC ratio)\n50V starting voltage\nMultiple MPPTs (3 and 4)\nIncludes a revenue grade meter (RGM)\nBuilt in Wi-Fi and Cellular communication (optional)\nLightweight (32 lb/45 lb)\n<10 mins commission with EI App (incl. Tigo TS4)',850.00,NULL,'/uploads/datasheets/1750494153025-hrclv8qyj2s.pdf','b5ef143e-4e72-11f0-bbc5-06479488ad4b','TSI-7.6K-US',0.00,'[]',0,'calculated',0.00,'tigo-76-kw-inverter-tsi-76k-us',0,'2025-06-19 14:04:13','2025-08-04 11:27:50'),('4b6cbc98-4ae2-11f0-bbc5-06479488ad4b','Qcells 395 Watt Black Bifacial Solar Panel','',80.00,NULL,NULL,'a0b3eb1a-4e72-11f0-bbc5-06479488ad4b','Q.Peak DUO BLK ML-G10+/t 395',0.00,'[]',0,'calculated',0.00,'qcells-395-watt-black-bifacial-solar-panel-qpeak-duo-blk-ml-g10t-395',0,'2025-06-16 18:47:03','2025-07-02 18:29:06'),('4ddc7c83-77c5-11f0-8e76-0637a5b9918d','SolarEdge 7.6 kW Single Phase Inverter','',560.00,NULL,NULL,'b5ef143e-4e72-11f0-bbc5-06479488ad4b','SE7600H-USSSHBC14',0.00,'[]',0,'calculated',0.00,'solaredge-76-kw-single-phase-inverter-se7600h-ussshbc14',1,'2025-08-12 21:42:54','2025-12-08 21:06:24'),('4e1a404a-6109-11f0-8e60-0637a5b9918d','Enphase IQ8+ Microinverter','<p>The Enphase IQ7HS-66-M-US microinverter is engineered for use with high-output 66-cell PV modules. Offering 384VA of continuous AC output power, it is ideal for pairing with solar panels rated between 420W and 500W. As part of the IQ Series, the IQ7HS integrates seamlessly with Enphase’s intelligent ecosystem, including IQ Gateway, IQ Combiner, IQ Batteries, and Enlighten monitoring. With built-in rapid shutdown and compliance with NEC and IEEE grid standards, it delivers top-tier safety, performance, and long-term value.</p><h3><strong>Key Benefits</strong></h3><p><strong>384VA Output:</strong> Delivers reliable AC conversion for high-efficiency 66-cell solar modules.</p><p><strong>Optimized for 420W–500W Panels:</strong> Perfect for modern residential installations seeking high energy yield.</p><p><strong>Plug-and-Play Compatibility:</strong> Installs easily with Enphase Q Cables and monitoring hardware.</p><p><strong>Integrated Safety Features:</strong> Includes built-in rapid shutdown for NEC 690.12 compliance.</p><p><strong>Advanced Monitoring:</strong> Tracks real-time performance through the Enphase App and Enlighten platform.</p><h3><strong>Special Technology</strong></h3><p><strong>Smart Grid Features:</strong> Supports ride-through, volt/VAR, and frequency/watt per IEEE 1547.</p><p><strong>Power Line Communication (PLC):</strong> Transmits performance data to IQ Gateway via existing wiring.</p><p><strong>Burst Mode Technology:</strong> Increases energy production during low-light periods like early mornings and cloudy days.</p><p><strong>Software-Defined Firmware:</strong> Enables remote updates and system optimization via Enlighten Cloud.</p><p><strong>Enphase Ecosystem Integration:</strong> Pairs with Enphase IQ Battery, System Controller, and Combiner seamlessly.</p><h3><strong>Warranty</strong></h3><p>The Enphase IQ7HS-66-M-US comes with a 25-year limited warranty when installed by an Enphase Certified Installer, guaranteeing long-term reliability and performance.</p><h3><strong>Best Use</strong></h3><p><strong>Residential Solar Systems:</strong> Designed for rooftops with 66-cell, high-efficiency PV modules.</p><p><strong>Smart Energy Homes:</strong> Fully compatible with battery-ready and grid-forming Enphase configurations.</p><p><strong>NEC-Compliant Projects:</strong> Built-in rapid shutdown ensures quick system shutdown for safety and code adherence.</p><p><strong>Performance-Focused Installations:</strong> Ideal for homes prioritizing maximum module-level output and efficiency.</p><h3><strong>Specifications Table</strong></h3><p>SpecificationDataModelEN-IQ7HS-66-M-USOutput Power384VANominal Voltage240V AC Split-PhaseRecommended Module Power420W – 500WMPPT Operating Voltage38 – 45VDC Voltage Range16 – 60VCEC Efficiency97.0%Grid ComplianceUL 1741 SA, IEEE 1547Rapid ShutdownYes (NEC 690.12 Compliant)MonitoringEnphase Enlighten (via IQ Gateway)CommunicationPLC (Power Line Communication)Enclosure RatingNEMA 6 (Outdoor Rated)Dimensions (L × W × H)8.3 × 6.9 × 1.2 inWeight~2.71 lbsWarranty25-Year Limited Warranty</p>',150.00,NULL,NULL,'b5ef143e-4e72-11f0-bbc5-06479488ad4b','IQ8PLUS-72-2-US',0.00,'[]',0,'calculated',0.00,'enphase-iq8-microinverter-iq8plus-72-2-us',1,'2025-07-14 23:21:44','2025-07-14 23:21:44'),('4ec7a044-bdf0-11f0-9ad4-0637a5b9918d','Sunpower 390 Watt Solar Panel','<p>These are nice SunPower 390 W solar panels.</p><p>The SunPower Performance Series 390W monocrystalline solar panel is designed for commercial use. It is built to be highly durable, resistant to harsh conditions like salt, acid, and ammonia, and can withstand significant mechanical loads. The \"COM\" in the SKU indicates its suitability for commercial-scale installations.&nbsp;</p><p><strong>Technical specifications</strong></p><ul><li><p><strong>Power Output:</strong> 390 Watts</p></li><li><p><strong>Cells:</strong> 120 monocrystalline PERC cells</p></li><li><p><strong>Dimensions:</strong> Approximately 81.4 inches x 39.3 inches x 1.81 inches</p></li><li><p><strong>Weight:</strong> Approximately 50.9 pounds (23.1 kg)</p></li><li><p><strong>Frame:</strong> 1.81\" thick anodized aluminum alloy</p></li><li><p><strong>Durability:</strong> Certified for environmental resistance, including salt, acid, and ammonia, and can handle mechanical loads up to 5400 Pa (front) and 2400 Pa (back)&nbsp;</p></li></ul><p><strong>Key features</strong></p><ul><li><p><a target=\"_blank\" rel=\"noopener noreferrer nofollow\" class=\"text-blue-600 underline GI370e\" href=\"https://www.google.com/search?q=Maxeon+cell+technology&amp;rlz=1C5GCEM_enUS1118US1118&amp;oq=SKU%3A+SPR-P19-390-COM&amp;gs_lcrp=EgZjaHJvbWUyBggAEEUYOTIGCAEQRRg60gEHMTc2ajBqN6gCALACAA&amp;sourceid=chrome&amp;ie=UTF-8&amp;mstk=AUtExfC_8gSuunZDw-OtyhsgrhzpAsloxi9ATvrS7VC3QrfonQKe4Y6O1lF_TZ5JKHRYG7eJa7oNjrCrd_-L_tJcuXY7iqUPcEnGTGzy_JZ8p7IlV_bhkEz1rodFHYuIgshke7iPKOK1pfMyTJDBE3pCME-GU182pkXOj4vmVwVB6FP8dig&amp;csui=3&amp;ved=2ahUKEwi74MGHnumQAxWuIUQIHbTzMtIQgK4QegQIBhAB\"><strong>Maxeon cell technology</strong></a><strong>:</strong> This technology is used in SunPower Performance panels to increase efficiency and improve performance in shaded conditions.</p></li><li><p><strong>High Reliability:</strong> The panels are built for longevity and backed by a 25-year product and performance warranty.</p></li><li><p><strong>Commercial Application:</strong> The \"COM\" designation signifies that this panel is suitable for large-scale commercial rooftop installations.&nbsp;</p></li></ul><table class=\"table-auto border-collapse border border-gray-300\" style=\"min-width: 50px\"><colgroup><col style=\"min-width: 25px\"><col style=\"min-width: 25px\"></colgroup><tbody><tr class=\"\"><td class=\"border border-gray-300 p-2\" colspan=\"1\" rowspan=\"1\"><p>Length</p></td><td class=\"border border-gray-300 p-2\" colspan=\"1\" rowspan=\"1\"><p>81.4in</p></td></tr><tr class=\"\"><td class=\"border border-gray-300 p-2\" colspan=\"1\" rowspan=\"1\"><p>Width</p></td><td class=\"border border-gray-300 p-2\" colspan=\"1\" rowspan=\"1\"><p>39.3in</p></td></tr><tr class=\"\"><td class=\"border border-gray-300 p-2\" colspan=\"1\" rowspan=\"1\"><p>Rated Power Output</p></td><td class=\"border border-gray-300 p-2\" colspan=\"1\" rowspan=\"1\"><p>390 W</p></td></tr><tr class=\"\"><td class=\"border border-gray-300 p-2\" colspan=\"1\" rowspan=\"1\"><p>Voltage (VOC)</p></td><td class=\"border border-gray-300 p-2\" colspan=\"1\" rowspan=\"1\"><p>52.3V</p></td></tr><tr class=\"\"><td class=\"border border-gray-300 p-2\" colspan=\"1\" rowspan=\"1\"><p>Maximum String Voltage</p></td><td class=\"border border-gray-300 p-2\" colspan=\"1\" rowspan=\"1\"><p>1000V</p></td></tr><tr class=\"\"><td class=\"border border-gray-300 p-2\" colspan=\"1\" rowspan=\"1\"><p>Number of cells</p></td><td class=\"border border-gray-300 p-2\" colspan=\"1\" rowspan=\"1\"><p>120</p></td></tr><tr class=\"\"><td class=\"border border-gray-300 p-2\" colspan=\"1\" rowspan=\"1\"><p>Cell Type</p></td><td class=\"border border-gray-300 p-2\" colspan=\"1\" rowspan=\"1\"><p>Monocrystalline</p></td></tr><tr class=\"\"><td class=\"border border-gray-300 p-2\" colspan=\"1\" rowspan=\"1\"><p>Rated Efficiency</p></td><td class=\"border border-gray-300 p-2\" colspan=\"1\" rowspan=\"1\"><p>18.9%</p></td></tr><tr class=\"\"><td class=\"border border-gray-300 p-2\" colspan=\"1\" rowspan=\"1\"><p>Connector Type</p></td><td class=\"border border-gray-300 p-2\" colspan=\"1\" rowspan=\"1\"><p>IP-67, Multi-Contact (MC4)</p></td></tr><tr class=\"\"><td class=\"border border-gray-300 p-2\" colspan=\"1\" rowspan=\"1\"><p>Backsheet Color</p></td><td class=\"border border-gray-300 p-2\" colspan=\"1\" rowspan=\"1\"><p>black</p></td></tr><tr class=\"\"><td class=\"border border-gray-300 p-2\" colspan=\"1\" rowspan=\"1\"><p>Frame Color</p></td><td class=\"border border-gray-300 p-2\" colspan=\"1\" rowspan=\"1\"><p>silver</p></td></tr><tr class=\"\"><td class=\"border border-gray-300 p-2\" colspan=\"1\" rowspan=\"1\"><p>Dimensions LxWxH</p></td><td class=\"border border-gray-300 p-2\" colspan=\"1\" rowspan=\"1\"><p>81.4 x 39.3 x 1.81 in</p></td></tr><tr class=\"\"><td class=\"border border-gray-300 p-2\" colspan=\"1\" rowspan=\"1\"><p>Weight</p></td><td class=\"border border-gray-300 p-2\" colspan=\"1\" rowspan=\"1\"><p>50.9 lbs</p></td></tr><tr class=\"\"><td class=\"border border-gray-300 p-2\" colspan=\"1\" rowspan=\"1\"><p>Pallet Qty</p></td><td class=\"border border-gray-300 p-2\" colspan=\"1\" rowspan=\"1\"><p>23</p></td></tr><tr class=\"\"><td class=\"border border-gray-300 p-2\" colspan=\"1\" rowspan=\"1\"><p>Manufacturer</p></td><td class=\"border border-gray-300 p-2\" colspan=\"1\" rowspan=\"1\"><p>SunPower</p></td></tr><tr class=\"\"><td class=\"border border-gray-300 p-2\" colspan=\"1\" rowspan=\"1\"><p>Manufacturer Part #</p></td><td class=\"border border-gray-300 p-2\" colspan=\"1\" rowspan=\"1\"><p>SPR-P19-390-COM</p></td></tr><tr class=\"\"><td class=\"border border-gray-300 p-2\" colspan=\"1\" rowspan=\"1\"><p>Operating Temperatures</p></td><td class=\"border border-gray-300 p-2\" colspan=\"1\" rowspan=\"1\"><p>−40°F to +185°F</p></td></tr><tr class=\"\"><td class=\"border border-gray-300 p-2\" colspan=\"1\" rowspan=\"1\"><p>Scope of Application</p></td><td class=\"border border-gray-300 p-2\" colspan=\"1\" rowspan=\"1\"><p>Solar Panels for Buildings</p></td></tr><tr class=\"\"><td class=\"border border-gray-300 p-2\" colspan=\"1\" rowspan=\"1\"><p>Use</p></td><td class=\"border border-gray-300 p-2\" colspan=\"1\" rowspan=\"1\"><ul><li><p>Commercial</p></li><li><p>Grid-Tie</p></li><li><p>Off-Grid</p></li><li><p>Residential</p></li></ul></td></tr><tr class=\"\"><td class=\"border border-gray-300 p-2\" colspan=\"1\" rowspan=\"1\"><p>Warranty</p></td><td class=\"border border-gray-300 p-2\" colspan=\"1\" rowspan=\"1\"><p>25 Year Product and Performance Warranty</p></td></tr></tbody></table>',85.00,NULL,'/uploads/datasheets/1763587451895-4sbb64aucgj.pdf','a0b3eb1a-4e72-11f0-bbc5-06479488ad4b','SPR-P19-390-COM',0.00,'[{\"type\":\"fixed\",\"name\":\"Standard Shipping\",\"description\":\"3-5 business days\",\"cost\":60},{\"type\":\"local_pickup\",\"name\":\"Local Pickup\",\"description\":\"Pick up from our location\",\"warehouse_ids\":[\"main-warehouse-id\",\"41ee39d4-51d5-11f0-bbc5-06479488ad4b\",\"east-warehouse-id\"]}]',0,'calculated',0.00,'sunpower-390-watt-solar-panel-spr-p19-390-com',1,'2025-11-10 04:47:05','2025-11-19 21:24:13'),('597c4f3a-8e78-11f0-95d2-0637a5b9918d','EG4 12000XP Off-Grid Inverter','<p>The EG4 12000XP is a high-capacity, split-phase off-grid inverter engineered to provide reliable, continuous power for homes, cabins, and remote properties. As the only ESS off-grid system of its kind, it supports up to 24 kW of PV input without a combiner box and maximizes solar production through dual MPPT tracking. Built for demanding off-grid environments, it delivers advanced system control, dependable battery integration, and scalable performance for long-term energy independence.</p><h2><strong>Key Benefits:</strong></h2><ul><li><p><strong>High-Voltage PV Input:</strong>&nbsp;Accepts up to 480 VDC and 24 kW of solar input, reducing cabling requirements and simplifying system design.</p></li><li><p><strong>Dual MPPT Optimization: </strong>Maximizes solar energy production by independently tracking two PV strings for stable performance in changing conditions.</p></li><li><p><strong>Built-In Wi-Fi Monitoring:</strong> Allows remote system monitoring and adjustments through the EG4 App or Monitor Center for added convenience and visibility.</p></li><li><p><strong>Closed-Loop Battery Communications:</strong>&nbsp;Integrates directly with EG4 48V batteries and supported brands for accurate charging, protections, and safe operation.</p></li><li><p><strong>Smart Load Port: </strong>Manages dedicated circuits or appliances through load shedding, AC coupling, or selective power delivery to increase system efficiency.</p></li><li><p><strong>Parallel Capability:</strong>&nbsp;Supports up to 16 units in parallel, enabling large systems up to 240 kW of total output.</p></li><li><p><strong>NEC-Compliant Safety:</strong>&nbsp;Rapid shutdown–ready (RSD) to meet NEC 690.12 safety requirements.</p></li></ul><h2><strong>Use Cases:</strong></h2><p>The EG4 12000XP is suited for residential homes, cabins, off-grid properties, and remote installations requiring dependable, high-output power. It also supports commercial and light industrial setups that need scalable energy storage and multi-inverter configurations. Ideal for hybrid systems, backup power applications, and full off-grid systems.</p><h2><strong>Tech Specs:</strong></h2><ul><li><p><strong>Nominal Power Output:</strong> 15,000W with PV input* / 12,000W without PV</p></li><li><p><strong>PV Input Capacity:</strong> Up to 24,000W (480 VDC max)</p></li><li><p><strong>Recommended Battery Capacity:</strong> &gt;400Ah per inverter</p></li><li><p><strong>Battery Communications:</strong> Closed-loop compatible with EG4 48V batteries + supported brands</p></li><li><p><strong>Connectivity:</strong> Plug-in Wi-Fi module for EG4 App / EG4 Monitor</p></li><li><p><strong>Dimensions:</strong> 34.25 × 20.87 × 5.91 in</p></li><li><p><strong>Weight:</strong> 104.7 lbs&nbsp;</p></li><li><p><strong>Operating Temperature:</strong> 32°F – 113°F (0°C – 45°C) @ full load</p></li></ul>',2970.00,NULL,'/uploads/datasheets/1764379472193-nv5j2u3p2aq.pdf','b5ef143e-4e72-11f0-bbc5-06479488ad4b','EG4INV12KXPV2US',0.00,'[{\"type\":\"free\",\"name\":\"Standard Shipping\",\"description\":\"3-5 business days\"}]',0,'calculated',0.00,'eg4-12000xp-off-grid-inverter-eg4inv12kxpv2us',1,'2025-09-10 18:59:59','2025-11-29 01:24:34'),('5a040c29-b52c-11f0-9ae1-0637a5b9918d','MC4 Male End Box Of 100','',150.00,NULL,NULL,NULL,'MC4-male-end-100',0.00,'[]',0,'calculated',0.00,'mc4-male-end-box-of-100-mc4-male-end-100',1,'2025-10-30 01:04:14','2025-10-30 15:21:03'),('5a3ad22c-4c93-11f0-bbc5-06479488ad4b','Canadian Solar 355 Watt Solar Panel','',55.00,NULL,NULL,'a0b3eb1a-4e72-11f0-bbc5-06479488ad4b','CS3U-355P',0.00,'[]',0,'calculated',0.00,'canadian-solar-355-watt-solar-panel-cs3u-355p',0,'2025-06-18 22:27:00','2025-07-02 18:26:53'),('6782421e-4e6f-11f0-bbc5-06479488ad4b','Alexus 405 Watt Black Solar Panel','<p>Among the newest offerings of Alexus Solar, ALEX-405-B-54-S is part of the ALEX-390~410-B-54-S series. These panels use state-of-the-art technology to achieve high efficiency and dependability. The Passivated Emitter Rear Contact (PERC) technology ensures excellent power output. This solar cell type employs an additional reflective layer to absorb more sunlight.</p><p>Half-cut cell technology adds a few more percent to the overall performance, making this model a great example of efficiency. Alexus Solar made solar cells in ALEX-405-B-54-S two times smaller than the standard size, thus reducing power loss and improving low-light behavior. As a result, the panel achieves an impressive efficiency of 20.7%. Novel design solutions allow this panel to look as well as it performs. This model is just 1.2\" in depth and is jet black with a sleek finish. The panel\'s functionality and durability are not affected by its aesthetic appeal though. Alexus Solar provides 25 years of product warranty and guarantees that after 25 years, performance will be at 85.04% or more.</p><ul><li><p>405 W power output</p></li><li><p>108 half-cut PERC cells</p></li><li><p>20.7% efficiency</p></li><li><p>1500 V DC maximum system voltage</p></li><li><p>MC4 compatible connectors</p></li><li><p>25-year product and 25-year performance warranties</p></li></ul>',99.00,NULL,'/uploads/datasheets/1750493527909-b9nbzurvcd.pdf','a0b3eb1a-4e72-11f0-bbc5-06479488ad4b','ALEX-405-B54-S',0.00,'[{\"type\":\"fixed\",\"name\":\"Standard Shipping\",\"description\":\"3-5 business days\",\"cost\":500},{\"type\":\"local_pickup\",\"name\":\"Local Pickup\",\"description\":\"Pick up from our location\",\"warehouse_ids\":[\"east-warehouse-id\",\"main-warehouse-id\",\"41ee39d4-51d5-11f0-bbc5-06479488ad4b\"]}]',0,'calculated',0.00,'alexus-405-watt-black-solar-panel-alex-405-b54-s',0,'2025-06-21 07:14:43','2025-12-13 13:13:49'),('67831fb8-9a79-11f0-8dbb-0637a5b9918d','APTOS MAC-800 Dual Unit | 2:1','<h1><strong>APTOS MAC-800 Dual Unit | 2:1 Trunk Version Microinverter</strong></h1><p>The high-performance MAC-800 dual unit microinverter is engineered for maximum AC power output when paired with Aptos Solar Technology’s high-power solar panels. The MAC-800 is built for simple system integration and is compatible with third-party devices. The MAC-800 is equipped and ready for system monitoring and trend tracking through Aptos Solar Technology’s cloud-based software.<br><br><strong>Key Features:</strong></p><ul><li><p>Up to 800W max output</p></li><li><p>Compatible with 120 &amp; 144 cell PV panels</p></li><li><p>IP67-rated enclosure for protection in harsh weather conditions</p></li><li><p>Built-in NEC compliant rapid shutdown feature</p></li><li><p>6,000V surge protection</p></li><li><p>Ambient temperature range (°C):&nbsp;-40° to +65°</p></li><li><p>&nbsp;Compliance: UL 1741, IEEE 1547, UL 1741 SA (240Vac), CA Rule 21 (240Vac), CSA C22.2 No. 107.1-16, FCC Part 15B, FCC Part 15C</p></li></ul>',220.00,NULL,'/uploads/datasheets/1758850718306-y1titofgi1.pdf','b5ef143e-4e72-11f0-bbc5-06479488ad4b','MAC-800R',0.00,'[{\"type\":\"fixed\",\"name\":\"Standard Shipping\",\"description\":\"3-5 business days\",\"cost\":9.99}]',0,'calculated',0.00,'aptos-mac-800-dual-unit-21-mac-800r',1,'2025-09-26 01:37:46','2025-09-26 01:39:37'),('697daa53-5a8f-11f0-8d93-0637a5b9918d','Shipping','',1.00,NULL,NULL